const EMBEDDED_DATA = {"dimensions": [{"id": "xiu-shen", "name": "修身与学习", "icon": "books", "description": "如何持续学习、提升认知、自我修养", "sort_order": 1}, {"id": "chuang-ye", "name": "创业与事业", "icon": "rocket", "description": "从零到一、建立事业的核心方法论", "sort_order": 2}, {"id": "tou-zi", "name": "投资与理财", "icon": "money", "description": "价值投资、资产配置、风险管理", "sort_order": 3}, {"id": "hun-yin", "name": "婚姻与亲密关系", "icon": "heart", "description": "选择伴侣、经营关系和家庭的核心智慧", "sort_order": 4}, {"id": "she-jiao", "name": "社交与人脉", "icon": "handshake", "description": "建立信任、发展人脉、团结力量", "sort_order": 5}, {"id": "shen-ti", "name": "身体健康与养生", "icon": "strong", "description": "身体是革命的本钱——中医养生与健康管理", "sort_order": 6}, {"id": "gong-zuo", "name": "工作方法", "icon": "bolt", "description": "高效工作、科学决策的方法与工具", "sort_order": 7}, {"id": "ling-dao", "name": "领导力与管理", "icon": "target", "description": "带团队、做决策、建组织的根本智慧", "sort_order": 8}, {"id": "qi-jia", "name": "齐家与教育", "icon": "home", "description": "经营家庭、教育子女的智慧与方法", "sort_order": 9}, {"id": "li-xiang", "name": "理想与境界", "icon": "star", "description": "人生的终极追求、价值观与精神境界", "sort_order": 10}], "figures": [{"id": "neill", "name": "亚历山大·尼尔", "short_name": "尼尔", "title": "夏山学校创始人", "description": "英国教育家，夏山学校的创办者，倡导自由教育的先驱。", "color": "#D35400"}, {"id": "vygotsky", "name": "列夫·维果茨基", "short_name": "维果茨基", "title": "发展心理学家", "description": "苏联著名心理学家，提出最近发展区理论，对社会文化发展理论有奠基性贡献。", "color": "#A569BD"}, {"id": "dweck", "name": "卡罗尔·德韦克", "short_name": "德韦克", "title": "成长型思维提出者", "description": "斯坦福大学心理学家，提出固定型思维与成长型思维理论，对教育领域影响深远。", "color": "#1ABC9C"}, {"id": "kongzi", "name": "孔子", "short_name": "孔子", "title": "儒家学派创始人", "description": "孔子（前551-前479）是儒家学派创始人，中国古代最伟大的思想家和教育家。其思想核心是仁、礼、中庸。", "color": "#D35400"}, {"id": "sunsimiao", "name": "孙思邈", "short_name": "孙思邈", "title": "药王", "description": "唐代著名医药学家，著有《千金要方》《千金翼方》，提出了系统的养生理论和方法。", "color": "#58D68D"}, {"id": "zhangzhongjing", "name": "张仲景", "short_name": "张仲景", "title": "医圣", "description": "东汉著名医学家，著有《伤寒杂病论》，确立了辩证论治的中医临床原则，被尊为医圣。", "color": "#2ECC71"}, {"id": "zengguofan", "name": "曾国藩", "short_name": "曾国藩", "title": "晚清名臣 · 理学家", "description": "曾国藩（1811-1872）是晚清中兴名臣，湘军创始人。他一生坚持修身齐家治国平天下，家书和日记是传统修身哲学的集大成者。", "color": "#8E44AD"}, {"id": "franklin", "name": "本杰明·富兰克林", "short_name": "富兰克林", "title": "美国开国元勋 · 发明家 · 作家", "description": "本杰明·富兰克林（1706-1790）是美国开国元勋之一，发明家、作家、外交家。他的《富兰克林自传》和十三条美德修身法影响深远。", "color": "#2980B9"}, {"id": "zhuyi", "name": "朱震亨", "short_name": "朱震亨", "title": "滋阴派创始人", "description": "元代著名医学家，金元四大家之一，提出了阳常有余阴常不足的养生思想。", "color": "#52BE80"}, {"id": "munger", "name": "查理·芒格", "short_name": "芒格", "title": "投资家 · 思想家 · 伯克希尔副董事长", "description": "查理·芒格（1924-2023）是沃伦·巴菲特的长期搭档，伯克希尔·哈撒韦的副董事长。以多元思维模型、误判心理学、能力圈等思想著称。", "color": "#1B4F72"}, {"id": "mao", "name": "毛泽东", "short_name": "毛主席", "title": "革命家 · 战略家 · 诗人", "description": "毛泽东（1893-1976）是中国共产党、中国人民解放军和中华人民共和国的主要创立者。他的哲学思想、军事思想和诗词创作对世界影响深远。", "color": "#922B21"}, {"id": "wangyangming", "name": "王阳明", "short_name": "王阳明", "title": "心学集大成者", "description": "王阳明（1472-1529），明代著名哲学家、军事家，心学集大成者。提出知行合一、致良知的思想。", "color": "#C0392B"}, {"id": "montessori", "name": "玛丽亚·蒙特梭利", "short_name": "蒙特梭利", "title": "儿童教育革命家", "description": "意大利第一位女医生，蒙特梭利教育法的创始人，强调儿童自主发展和有准备的环境。", "color": "#E67E22"}, {"id": "chapman", "name": "盖瑞·查普曼", "short_name": "查普曼", "title": "婚姻辅导专家", "description": "盖瑞·查普曼博士是《爱的五种语言》作者，全球知名的婚姻辅导专家。", "color": "#AF7AC5"}, {"id": "nelsen", "name": "简·尼尔森", "short_name": "尼尔森", "title": "正面管教创始人", "description": "简·尼尔森是正面管教理论的创始人，倡导和善而坚定的教育理念。", "color": "#F39C12"}, {"id": "gottman", "name": "约翰·戈特曼", "short_name": "戈特曼", "title": "婚姻研究泰斗", "description": "约翰·戈特曼是华盛顿大学心理学教授，通过对上千对夫妻的长期观察研究，提出了婚姻幸福的科学法则。", "color": "#117A65"}, {"id": "bowlby", "name": "约翰·鲍比", "short_name": "鲍比", "title": "依恋理论创始人", "description": "约翰·鲍比是英国心理学家，依恋理论的奠基人，对儿童发展和亲密关系研究产生了革命性影响。", "color": "#5DADE2"}, {"id": "sternberg", "name": "罗伯特·斯滕伯格", "short_name": "斯滕伯格", "title": "爱情心理学专家", "description": "罗伯特·斯滕伯格提出了爱情三角理论，是当代爱情心理学的重要理论家。", "color": "#48C9B0"}, {"id": "miller", "name": "罗兰·米勒", "short_name": "米勒", "title": "亲密关系研究权威", "description": "罗兰·米勒是美国心理学家，以《亲密关系》一书闻名，系统整合了人际关系科学数十年的研究成果。", "color": "#2E86C1"}, {"id": "laozi", "name": "老子", "short_name": "老子", "title": "道家学派创始人", "description": "老子，春秋时期思想家，道家学派创始人，著有《道德经》。其思想以道为核心，主张无为而治、顺应自然。", "color": "#16A085"}, {"id": "chenheqin", "name": "陈鹤琴", "short_name": "陈鹤琴", "title": "中国幼教之父", "description": "陈鹤琴是中国现代幼儿教育的奠基人，提出活教育理论，是中国教育史上的重要人物。", "color": "#2874A6"}, {"id": "aurelius", "name": "马可·奥勒留", "short_name": "奥勒留", "title": "罗马皇帝 · 斯多葛哲学家", "description": "马可·奥勒留（121-180）是罗马五贤帝之一，斯多葛哲学代表。他的《沉思录》探讨了理性、道德、内心平静等永恒主题。", "color": "#7F8C8D"}, {"id": "huangdi", "name": "黄帝内经", "short_name": "黄帝内经", "title": "中医经典之首", "description": "中国最早的医学典籍，奠定了中医学的理论基础，被誉为医之始祖，涵盖养生、病理、诊断、治疗等。", "color": "#27AE60"}], "entries": [{"id": 1, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "每天起床的时候，争取变得比你从前更聪明一点。慢慢地，你会有所进步。每天慢慢往前挪一点。到最后——如果你足够长寿的话——大多数人得到了他们应得的东西。", "source": "《穷查理宝典》", "interpretation": "复利不仅适用于财富，也适用于知识。每天进步一点点，长期积累的效果惊人。", "tags": "学习,复利,终身学习,积累", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 2, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "方法", "quote": "我见过的所有聪明人，没有一个不大量阅读的——没有，一个都没有。", "source": "伯克希尔股东大会", "interpretation": "阅读是构建多元思维模型的基础。芒格被称为长着两条腿的书架。", "tags": "阅读,学习,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 3, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "手里拿着锤子的人，看什么都像钉子。", "source": "《穷查理宝典》", "interpretation": "单一学科视角是认知的最大局限。必须建立多学科的思维模型格栅。", "tags": "多元思维,认知,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 4, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "好好学习，天天向上。", "source": "1949年题词", "interpretation": "最简单也最深刻的劝学箴言。学的方向、学的方法、学的态度，都在八个字里。", "tags": "学习,成长", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 5, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "读书是学习，使用也是学习，而且是更重要的学习。", "source": "《中国革命战争的战略问题》1936", "interpretation": "理论必须联系实际。从实践中学习、在干中学，才是真正有效的学习方式。", "tags": "学习,实践,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 6, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "方法论", "quote": "没有调查就没有发言权。", "source": "《反对本本主义》1930", "interpretation": "不了解情况就不要轻易下结论。既是学习方法，也是决策原则。", "tags": "调查,学习,决策", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 7, "figure_id": "munger", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "找到一个你感兴趣并且有天赋的领域，然后全身心投入。", "source": "南加州大学演讲", "interpretation": "事业成功的起点是兴趣与能力的交叉点。不要为了钱去做自己不喜欢的事。", "tags": "创业,事业,热情", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "创业与事业"}, {"id": 8, "figure_id": "munger", "dimension_id": "chuang-ye", "category": "投资哲学", "quote": "最好的生意是拥有护城河的生意。护城河可以是品牌、专利、规模优势、网络效应或者特许经营权。", "source": "《穷查理宝典》", "interpretation": "建立持续的竞争优势是事业长青的关键。", "tags": "护城河,竞争,商业", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "创业与事业"}, {"id": 9, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "方法论", "quote": "调查就像十月怀胎，解决问题就像一朝分娩。调查就是解决问题。", "source": "《反对本本主义》", "interpretation": "创业初期不要急于行动，先把市场、用户、竞争格局调查清楚。", "tags": "创业,调研,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 10, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "方法论", "quote": "集中优势兵力，各个歼灭敌人。", "source": "《集中优势兵力，各个歼灭敌人》1946", "interpretation": "创业者在资源有限时聚焦到最有可能突破的点上，打歼灭战而不是消耗战。", "tags": "战略,聚焦,创业", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 11, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "以合理的价格买入优秀的公司，远胜于以便宜的价格买入平庸的公司。", "source": "《穷查理宝典》", "interpretation": "质量比价格更重要。好公司即使买得稍贵，长期回报也远超烂公司的便宜货。", "tags": "价值投资,质量,长期", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 12, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "一生只需做少数几个重大的决策，然后持有。剩下的时间，你什么都不用做，坐在那里等着就好。", "source": "Daily Journal 股东大会", "interpretation": "投资不是越勤奋回报越高。关键在于少数几个关键决策的正确性。", "tags": "耐心,长期,少即是多", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 13, "figure_id": "munger", "dimension_id": "tou-zi", "category": "方法论", "quote": "如果我知道我会死在哪里，我就永远不会去那个地方。", "source": "哈佛大学演讲", "interpretation": "反过来想——与其研究如何成功，不如先研究如何避免失败。", "tags": "反向思维,风险,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 14, "figure_id": "mao", "dimension_id": "tou-zi", "category": "方法论", "quote": "不打无准备之仗，不打无把握之仗。每战都应力求有准备。", "source": "《目前形势和我们的任务》", "interpretation": "投资中的每笔交易都应该是有所准备的：充分研究、设定赔率、控制仓位。", "tags": "准备,风险,投资", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "投资与理财"}, {"id": 15, "figure_id": "mao", "dimension_id": "tou-zi", "category": "方法论", "quote": "战略上藐视敌人，战术上重视敌人。", "source": "《关于目前党的政策中的几个重要问题》", "interpretation": "长期投资中要相信复利的力量，但每一次具体的投资决策要极度审慎。", "tags": "战略,战术,心态", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "投资与理财"}, {"id": 16, "figure_id": "munger", "dimension_id": "hun-yin", "category": "人生智慧", "quote": "找到一位好配偶的最佳办法是你先成为一位好配偶。", "source": "《穷查理宝典》", "interpretation": "在关系中你唯一能控制的是你自己。想要什么样的伴侣，先成为什么样的人。", "tags": "婚姻,修身,关系", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "婚姻与亲密关系"}, {"id": 17, "figure_id": "munger", "dimension_id": "hun-yin", "category": "人生智慧", "quote": "和比你强的人结婚。和比你强的人一起生活，你会变得更好。这是你一生中最重要的决定。", "source": "伯克希尔股东大会", "interpretation": "选择伴侣是人生最重要的投资之一。找到一个能让你变得更好的人，比任何财富都重要。", "tags": "婚姻,选择,成长", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "婚姻与亲密关系"}, {"id": 18, "figure_id": "mao", "dimension_id": "hun-yin", "category": "思想", "quote": "婚姻应以爱情为基础，提倡男女平等，反对男尊女卑。", "source": "新中国成立后婚姻法改革", "interpretation": "婚姻法改革第一次从法律上确立婚姻自由、男女平等。", "tags": "婚姻,平等,社会变革", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "婚姻与亲密关系"}, {"id": 19, "figure_id": "munger", "dimension_id": "she-jiao", "category": "人生智慧", "quote": "信任是最重要的社交货币。你的声誉可能需要20年才能建立，但5分钟就能毁掉。", "source": "《穷查理宝典》", "interpretation": "不要做任何可能损害你声誉的事。信任一旦失去，几乎不可能重建。", "tags": "信任,声誉,社交", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "社交与人脉"}, {"id": 20, "figure_id": "munger", "dimension_id": "she-jiao", "category": "方法论", "quote": "和优秀的人在一起，你也会变得优秀。", "source": "《穷查理宝典》", "interpretation": "选择你的圈子。圈子是你认知和行为的平均。选对人，事就成了大半。", "tags": "社交,选择,圈子", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "社交与人脉"}, {"id": 21, "figure_id": "mao", "dimension_id": "she-jiao", "category": "方法论", "quote": "把朋友搞得多多的，把敌人搞得少少的。", "source": "抗战时期统战思想", "interpretation": "人际关系中的统一战线——尽可能扩大合作面，缩小对立面。这是战略智慧。", "tags": "社交,统战,战略", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "社交与人脉"}, {"id": 22, "figure_id": "mao", "dimension_id": "she-jiao", "category": "方法论", "quote": "团结一切可以团结的力量。", "source": "《论联合政府》", "interpretation": "不要因为小分歧就放弃大合作。在原则不动摇的前提下尽可能扩大共识。", "tags": "团结,合作,社交", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "社交与人脉"}, {"id": 23, "figure_id": "munger", "dimension_id": "shen-ti", "category": "人生智慧", "quote": "长寿的秘诀：不嫉妒，不怨恨，不过度消费。保持乐观，和快乐的人在一起。", "source": "《穷查理宝典》", "interpretation": "芒格活到99岁，长寿哲学极其简单：心地坦然、情绪稳定、生活节制。", "tags": "长寿,心态,健康", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "身体健康与养生"}, {"id": 24, "figure_id": "mao", "dimension_id": "shen-ti", "category": "经典语录", "quote": "身体是革命的本钱。", "source": "毛泽东名言", "interpretation": "没有健康的身体，一切理想都是空谈。毛主席一生热爱游泳和登山，73岁还畅游长江。", "tags": "健康,本钱,革命", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "身体健康与养生"}, {"id": 25, "figure_id": "mao", "dimension_id": "shen-ti", "category": "故事", "quote": "游泳最大的好处是能锻炼意志。水很冷的时候，你敢不敢下？敢下，就锻炼了。", "source": "毛主席谈体育锻炼", "interpretation": "身体健康不只是生理问题，更是意志问题。在舒适区之外锤炼自己。", "tags": "锻炼,意志,健康", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "身体健康与养生"}, {"id": 26, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "用检查清单工作。飞行员、医生都用清单，为什么投资者不用？", "source": "《穷查理宝典》", "interpretation": "在重要决策前使用检查清单，避免因遗漏或情绪干扰而出错。", "tags": "清单,方法,决策", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 27, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "双轨分析——先理性分析所有因素，再分析哪些心理偏误可能影响判断。", "source": "哈佛大学演讲", "interpretation": "真正的理性是把心理偏误也纳入分析框架。", "tags": "分析,心理,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 28, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "解剖麻雀——深入一个点，把问题彻底搞透，就能举一反三。", "source": "《工作方法六十条》", "interpretation": "与其泛泛了解一百个问题，不如把一个点彻底搞透。", "tags": "方法,深入,分析", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 29, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "以点带面，典型引路。突破一点，带动全局。", "source": "《工作方法六十条》", "interpretation": "工作中先抓一个试点，成功了再推广。降低试错成本。", "tags": "试点,推广,方法", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 30, "figure_id": "munger", "dimension_id": "ling-dao", "category": "方法论", "quote": "以身作则是最重要的领导力。如果你要求别人做什么，你先做到。", "source": "伯克希尔股东大会", "interpretation": "管理者的行为比任何规章制度都更有说服力。", "tags": "领导力,以身作则,管理", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "领导力与管理"}, {"id": 31, "figure_id": "munger", "dimension_id": "ling-dao", "category": "方法论", "quote": "选对人比培养人更重要。", "source": "《穷查理宝典》", "interpretation": "招聘是最重要的管理决策。选到对的人，管理就成功了一半。", "tags": "招聘,用人,管理", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "领导力与管理"}, {"id": 32, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "领导者的责任，归结起来，主要是出主意、用干部两件事。", "source": "《中国共产党在民族战争中的地位》", "interpretation": "管理者的核心工作就两件：定方向和用对人。", "tags": "领导力,战略,用人", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 33, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "从群众中来，到群众中去。集中起来，坚持下去。", "source": "《关于领导方法的若干问题》", "interpretation": "好的决策来自一线，好的执行回到一线。", "tags": "群众路线,决策,执行", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 34, "figure_id": "munger", "dimension_id": "qi-jia", "category": "人生智慧", "quote": "身教重于言传。你对孩子最重要的教育不是你说什么，而是你做什么。", "source": "《穷查理宝典》", "interpretation": "芒格自己就是终生阅读者的典范，教育孩子的最好方式是自己先做好榜样。", "tags": "教育,榜样,家庭", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "齐家与教育"}, {"id": 35, "figure_id": "munger", "dimension_id": "qi-jia", "category": "人生智慧", "quote": "给孩子最好的礼物是：良好的价值观、良好的教育、阅读的习惯。", "source": "伯克希尔股东大会", "interpretation": "物质财富会消散，但价值观、教育、习惯是一辈子的财富。", "tags": "教育,价值观,家庭", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "齐家与教育"}, {"id": 36, "figure_id": "mao", "dimension_id": "qi-jia", "category": "家风", "quote": "恋亲不为亲徇私，念旧不为旧谋利，济亲不为亲撑腰。", "source": "毛主席家风原则", "interpretation": "在家庭与公义之间划出清晰边界。不因亲情而损害原则。", "tags": "家风,原则,教育", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "齐家与教育"}, {"id": 37, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "理性是一种道德责任。你有责任保持理性，因为你的非理性会伤害别人。", "source": "《穷查理宝典》", "interpretation": "理性不只是智商问题，更是一种道德选择。需要强大的内心。", "tags": "理性,道德,境界", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 38, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "真正的富有不是拥有很多钱，而是拥有一个丰富的内心世界。", "source": "Daily Journal 股东大会", "interpretation": "芒格一生节俭，精神富足比物质富足重要得多。", "tags": "富有,内心,境界", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 39, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "为人民服务。", "source": "《为人民服务》1944", "interpretation": "五个字道尽人生最高境界。", "tags": "奉献,境界,理想", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 40, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "星星之火，可以燎原。", "source": "《星星之火，可以燎原》1930", "interpretation": "在最微小的力量中看到改变世界的力量。", "tags": "信念,希望,理想", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 41, "figure_id": "mao", "dimension_id": "li-xiang", "category": "诗词", "quote": "雄关漫道真如铁，而今迈步从头越。", "source": "《忆秦娥·娄山关》1935", "interpretation": "没有什么过不去的坎。", "tags": "诗词,勇气,信念", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 42, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "人与人之间产生吸引力的基本假设是：他人的出现对我们有奖赏意义。影响吸引力的因素包括接近性、相似性和互惠性。", "source": "《亲密关系》第3章", "interpretation": "多接触、找共同点、表现好感——这是建立亲密关系最基础的三步。", "tags": "吸引力,接近,相似,互惠", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 43, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "依恋类型分为安全型、焦虑型、回避型三种。安全型的人更容易建立健康稳定的亲密关系。", "source": "《亲密关系》第6章", "interpretation": "了解自己的依恋类型是改善亲密关系的第一步。安全型是最理想的状态，但后天可以调整。", "tags": "依恋理论,安全型,关系", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 44, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "亲密关系的满意度取决于：奖赏减去成本。但真正维系长期关系的是承诺——希望关系继续的主观意愿。", "source": "《亲密关系》第10章", "interpretation": "不要只计算眼前的得失，承诺是关系穿越低谷的保障。", "tags": "承诺,满意度,长期", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 45, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "高质量沟通的核心是：精确表述、积极倾听、保持礼貌和确认对方。沟通不良是关系破裂的首要原因。", "source": "《亲密关系》第8章", "interpretation": "吵架时试试：用第一人称表达感受（我感到...），而不是指责对方。", "tags": "沟通,倾听,表达", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 46, "figure_id": "gottman", "dimension_id": "hun-yin", "category": "核心理论", "quote": "幸福的婚姻基于深厚的友谊——彼此熟悉对方的世界，这种了解被称为爱情地图。", "source": "《幸福的婚姻》", "interpretation": "爱情地图需要不断更新。定期了解伴侣最近在想什么、在忙什么、有什么新变化。", "tags": "爱情地图,婚姻,友谊", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·戈特曼", "dimension_name": "婚姻与亲密关系"}, {"id": 47, "figure_id": "gottman", "dimension_id": "hun-yin", "category": "预警", "quote": "婚姻有四大致命沟通方式：批评、鄙视、辩护、冷战。尤其鄙视是最危险的信号。", "source": "《幸福的婚姻》", "interpretation": "若发现自己在关系中频繁使用这四种沟通方式，说明关系已经亮起红灯。", "tags": "批评,鄙视,冷战,预警", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·戈特曼", "dimension_name": "婚姻与亲密关系"}, {"id": 48, "figure_id": "gottman", "dimension_id": "hun-yin", "category": "核心理论", "quote": "健康婚姻中积极互动与消极互动的比例至少为5:1。一个批评需要五个温暖时刻来弥补。", "source": "《幸福的婚姻》", "interpretation": "刻意增加日常的小温暖——问候、微笑、感谢——这些小事构筑了关系的免疫系统。", "tags": "积极互动,婚姻,修复", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·戈特曼", "dimension_name": "婚姻与亲密关系"}, {"id": 49, "figure_id": "chapman", "dimension_id": "hun-yin", "category": "核心理论", "quote": "每个人都有自己偏好的爱的语言：肯定的言辞、精心的时刻、接受礼物、服务的行动、身体的接触。", "source": "《爱的五种语言》", "interpretation": "用对方偏爱的语言表达爱，而不是用你以为好的方式。对一个人好的方式，可能不是对方需要的。", "tags": "爱的语言,表达,理解", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "盖瑞·查普曼", "dimension_name": "婚姻与亲密关系"}, {"id": 50, "figure_id": "bowlby", "dimension_id": "hun-yin", "category": "核心理论", "quote": "童年与照顾者形成的依恋关系会深刻影响成年后的亲密关系模式。安全的依恋是健康发展的基础。", "source": "依恋理论", "interpretation": "童年经历塑造了我们在关系中的行为模式。觉察自己的模式是改变的第一步。", "tags": "依恋,童年,安全基地", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·鲍比", "dimension_name": "婚姻与亲密关系"}, {"id": 51, "figure_id": "sternberg", "dimension_id": "hun-yin", "category": "核心理论", "quote": "完美的爱情由三个成分构成：亲密（情感连接）、激情（驱动力）、承诺（决定维持关系）。三者缺一不可。", "source": "爱情三角理论", "interpretation": "热恋之初激情澎湃，但长期关系需要三者均衡发展。婚姻的本质是承诺的持续巩固。", "tags": "爱情三角,亲密,激情,承诺", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗伯特·斯滕伯格", "dimension_name": "婚姻与亲密关系"}, {"id": 52, "figure_id": "gottman", "dimension_id": "hun-yin", "category": "方法", "quote": "婚姻中69%的问题是无解的，源于性格差异。幸福夫妻的秘诀不是解决所有问题，而是学会与问题共处。", "source": "《幸福的婚姻》", "interpretation": "别试图改造对方。接受彼此的差异，找到共处的方式，比强行解决问题更明智。", "tags": "差异,接纳,共处", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·戈特曼", "dimension_name": "婚姻与亲密关系"}, {"id": 53, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "自我表露是亲密关系发展的核心机制。适当逐步地分享个人信息能显著增强亲密感。", "source": "《亲密关系》", "interpretation": "关系需要逐步深入，不要一开始就全盘托出，也不要长期封闭自己。节奏比速度重要。", "tags": "自我表露,亲密,信任建立", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 54, "figure_id": "gottman", "dimension_id": "hun-yin", "category": "方法", "quote": "柔和的开始对话是解决冲突的第一步。用抱怨代替指责，用请求代替要求。", "source": "《幸福的婚姻》", "interpretation": "想把事情谈好？第一句话的语气就决定了结局。别以攻击开始。", "tags": "冲突解决,沟通技巧,柔和", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·戈特曼", "dimension_name": "婚姻与亲密关系"}, {"id": 55, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "关系的消亡往往不是因为巨大的冲突，而是因为日常的忽视和疏离。珍惜日常的细微互动。", "source": "《亲密关系》", "interpretation": "大冲突可以修复，但日复一日的冷漠慢慢杀死关系。重视日常的联结。", "tags": "日常,忽视,联结", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 56, "figure_id": "bowlby", "dimension_id": "hun-yin", "category": "核心理论", "quote": "人类天生具有与重要他人建立亲密联结的需求。被理解、被支持、被接纳是基本心理需求。", "source": "依恋理论", "interpretation": "承认自己对亲密关系的需求不是软弱，而是人类本能。", "tags": "需求,联结,安全", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "约翰·鲍比", "dimension_name": "婚姻与亲密关系"}, {"id": 57, "figure_id": "montessori", "dimension_id": "qi-jia", "category": "核心理论", "quote": "儿童具有吸收性心智（0-6岁），无需刻意教导，通过环境中的体验就能自然地学习和发展。", "source": "蒙特梭利教育法", "interpretation": "为孩子创造丰富的环境比直接教更重要。语言、文化、社交能力都在日常环境中自然吸收。", "tags": "吸收性心智,蒙特梭利,环境", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "玛丽亚·蒙特梭利", "dimension_name": "齐家与教育"}, {"id": 58, "figure_id": "montessori", "dimension_id": "qi-jia", "category": "核心理论", "quote": "儿童发展有特定的敏感期：语言敏感期（0-6岁）、秩序敏感期（2-4岁）、感官精致化敏感期（2-6岁）等。", "source": "蒙特梭利教育法", "interpretation": "在敏感期内，儿童学习某种能力事半功倍。错过了虽然可以补，但难度大得多。", "tags": "敏感期,蒙特梭利,发展", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "玛丽亚·蒙特梭利", "dimension_name": "齐家与教育"}, {"id": 59, "figure_id": "montessori", "dimension_id": "qi-jia", "category": "核心理论", "quote": "有准备的环境是教育的核心——环境应该适应儿童的发展需要，而非让儿童适应环境。", "source": "蒙特梭利教育法", "interpretation": "在家里设置低矮的家具、可触及的用品、适合孩子尺寸的工具，让孩子能自主行动。", "tags": "环境,自主,蒙特梭利", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "玛丽亚·蒙特梭利", "dimension_name": "齐家与教育"}, {"id": 60, "figure_id": "montessori", "dimension_id": "qi-jia", "category": "核心理论", "quote": "跟随儿童。成人不应强迫儿童学习，而应观察儿童的兴趣和发展的需求，提供合适的引导。", "source": "蒙特梭利教育法", "interpretation": "尊重孩子的节奏和选择。你的任务是观察和准备，而不是推动和安排。", "tags": "跟随儿童,观察,引导", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "玛丽亚·蒙特梭利", "dimension_name": "齐家与教育"}, {"id": 61, "figure_id": "nelsen", "dimension_id": "qi-jia", "category": "核心理论", "quote": "正面管教的核心理念是和善而坚定。和善表达尊重，坚定尊重自己和规则。", "source": "《正面管教》", "interpretation": "既不要溺爱（和善不坚定），也不要严厉（坚定不和善）。中间那条路最难也最有效。", "tags": "正面管教,和善,坚定", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "简·尼尔森", "dimension_name": "齐家与教育"}, {"id": 62, "figure_id": "nelsen", "dimension_id": "qi-jia", "category": "核心理论", "quote": "错误是学习的好机会。孩子犯错时，重点不是惩罚，而是引导他从错误中学习和成长。", "source": "《正面管教》", "interpretation": "惩罚教会孩子的是如何逃避惩罚，而不是如何改正。让孩子从后果中学习。", "tags": "错误,学习,成长", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "简·尼尔森", "dimension_name": "齐家与教育"}, {"id": 63, "figure_id": "vygotsky", "dimension_id": "qi-jia", "category": "核心理论", "quote": "最近发展区：孩子独立解决问题的能力与在成人帮助下能解决的问题之间的差距，是最佳教学区。", "source": "最近发展区理论", "interpretation": "教孩子要在他的最近发展区内：太难会挫败，太简单会无聊。帮他够一够能到的地方。", "tags": "最近发展区,教学,脚手架", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "列夫·维果茨基", "dimension_name": "齐家与教育"}, {"id": 64, "figure_id": "neill", "dimension_id": "qi-jia", "category": "核心理论", "quote": "给孩子自由，让他们按自己的意愿发展，但同时让他们承担自己选择的后果。自由与责任是一体两面。", "source": "《夏山学校》", "interpretation": "过度管教会扼杀孩子的内在动力。真正的教育是信任孩子有自我发展的能力。", "tags": "自由,责任,夏山学校", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "亚历山大·尼尔", "dimension_name": "齐家与教育"}, {"id": 65, "figure_id": "chenheqin", "dimension_id": "qi-jia", "category": "核心理论", "quote": "活教育理论：做中教、做中学、做中求进步。凡是儿童自己能做的，让他自己做。", "source": "陈鹤琴教育思想", "interpretation": "动手实践是儿童最好的学习方式。包办代替不仅累了自己，也剥夺了孩子成长的机会。", "tags": "活教育,实践,自主", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "陈鹤琴", "dimension_name": "齐家与教育"}, {"id": 66, "figure_id": "dweck", "dimension_id": "qi-jia", "category": "核心理论", "quote": "成长型思维：相信能力可以通过努力提升。固定型思维：认为能力是固定的，无法改变。", "source": "《终身成长》", "interpretation": "表扬孩子的努力和策略，而不是天赋。被夸聪明的孩子倾向于回避挑战，被夸努力的孩子越挫越勇。", "tags": "成长型思维,表扬,努力", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "卡罗尔·德韦克", "dimension_name": "齐家与教育"}, {"id": 67, "figure_id": "dweck", "dimension_id": "qi-jia", "category": "核心理论", "quote": "培养成长型思维的关键：接受挑战、从失败中学习、把困难视为成长的机会。", "source": "《终身成长》", "interpretation": "让孩子明白：现在不会不等于永远不会。挑战越大，成长越大。", "tags": "挑战,失败,成长", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "卡罗尔·德韦克", "dimension_name": "齐家与教育"}, {"id": 68, "figure_id": "montessori", "dimension_id": "qi-jia", "category": "核心理论", "quote": "教育的目标不是填鸭知识，而是帮助儿童发展出独立的思考能力、自控力和对世界的好奇心。", "source": "蒙特梭利教育法", "interpretation": "教育不是为学校做准备，而是为生活做准备。", "tags": "教育目标,独立,好奇", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "玛丽亚·蒙特梭利", "dimension_name": "齐家与教育"}, {"id": 69, "figure_id": "nelsen", "dimension_id": "qi-jia", "category": "方法", "quote": "正面管教的长期目标不是让孩子听话，而是培养孩子的自律、责任感、合作精神和解决问题的能力。", "source": "《正面管教》", "interpretation": "每次教育孩子时间问自己：我这个行为是在培养他的长期品格，还是只求眼前的安静？", "tags": "长期目标,自律,责任", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "简·尼尔森", "dimension_name": "齐家与教育"}, {"id": 70, "figure_id": "vygotsky", "dimension_id": "qi-jia", "category": "核心理论", "quote": "学习发生在社会互动中，通过与他人的合作和对话，儿童内化了更高层次的思维能力。", "source": "社会文化理论", "interpretation": "让孩子与比自己能力稍强的同伴或成人一起学习，效果最好。", "tags": "社会互动,合作,内化", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "列夫·维果茨基", "dimension_name": "齐家与教育"}, {"id": 71, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "上古之人，其知道者，法于阴阳，和于术数，食饮有节，起居有常，不妄作劳，故能形与神俱，而尽终其天年，度百岁乃去。", "source": "《黄帝内经·素问·上古天真论》", "interpretation": "养生最根本的原则：顺应自然规律、饮食有节制、作息有规律、不过度劳累。做到这四点，健康长寿不难。", "tags": "养生,阴阳,饮食,作息", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 72, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "春三月，此谓发陈，天地俱生，万物以荣，夜卧早起，广步于庭。夏三月，此谓蕃秀，天地气交，万物华实，夜卧早起，无厌于日。", "source": "《黄帝内经·素问·四气调神大论》", "interpretation": "春夏养阳——春天晚睡早起多活动，夏天晚睡早起不厌烦阳光。顺应四时调整作息是养生根本。", "tags": "四季养生,作息,顺应自然", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 73, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "秋三月，此谓容平，天气以急，地气以明，早卧早起，与鸡俱兴。冬三月，此谓闭藏，水冰地坼，无扰乎阳，早卧晚起，必待日光。", "source": "《黄帝内经·素问·四气调神大论》", "interpretation": "秋冬养阴——秋天早睡早起，冬天早睡晚起等太阳出来。跟着太阳走，身体自然好。", "tags": "四季养生,秋冬,收藏", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 74, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理念", "quote": "正气存内，邪不可干。", "source": "《黄帝内经·素问·刺法论》", "interpretation": "身体的正气充足，外邪就难以入侵。养生的核心是提升自身的免疫力，而非盲目对抗病菌。", "tags": "免疫力,正气,预防", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 75, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理念", "quote": "上工治未病，不治已病；中工治欲病，不治已病；下工治已病。", "source": "《黄帝内经》", "interpretation": "最好的医生是预防疾病，而不是等病了再治。养成好的生活习惯就是最好的治疗。", "tags": "治未病,预防,养生", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 76, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "怒伤肝、喜伤心、思伤脾、忧伤肺、恐伤肾。", "source": "《黄帝内经·素问·阴阳应象大论》", "interpretation": "情绪管理是养生的关键一环。过度的情绪波动直接伤害五脏。保持情绪平和对健康至关重要。", "tags": "情志,五脏,情绪", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 77, "figure_id": "sunsimiao", "dimension_id": "shen-ti", "category": "方法", "quote": "养生十三法：发常梳、目常运、齿常叩、耳常鼓、面常洗、头常摇、腰常摆、腹常揉、膝常扭、脚常搓、常散步、常提肛、常深呼吸。", "source": "《千金要方》", "interpretation": "孙思邈活了141岁，他的养生方法简单易行。每天花几分钟做一遍，长期坚持效果显著。", "tags": "养生法,药王,日常保健", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "孙思邈", "dimension_name": "身体健康与养生"}, {"id": 78, "figure_id": "sunsimiao", "dimension_id": "shen-ti", "category": "核心理念", "quote": "口中言少，心中事少，腹里食少，自然睡少，依此四少，神仙诀了。", "source": "《千金要方》", "interpretation": "少说话养气、少操心养神、少吃饭养身、少赖床养生。四少原则是养生的精髓。", "tags": "养生口诀,少,孙思邈", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "孙思邈", "dimension_name": "身体健康与养生"}, {"id": 79, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "夫百病之始生也，皆生于风雨寒暑，阴阳喜怒，饮食居处，大惊卒恐。", "source": "《黄帝内经·灵枢》", "interpretation": "疾病的根源不外乎：外感六淫（风、寒、暑、湿、燥、火）、内伤七情（喜、怒、忧、思、悲、恐、惊）、饮食不节、起居失常。", "tags": "病因,六淫,七情", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 80, "figure_id": "zhuyi", "dimension_id": "shen-ti", "category": "核心理念", "quote": "阳常有余，阴常不足。但阴虚而病者，十之八九。养生之道，以养阴为要。", "source": "《格致余论》", "interpretation": "现代人熬夜、用眼过度、压力大都在耗阴。养阴比补阳更重要。早点睡就是最好的养阴。", "tags": "滋阴,养生,作息", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "朱震亨", "dimension_name": "身体健康与养生"}, {"id": 81, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "饮食自倍，肠胃乃伤。", "source": "《黄帝内经·素问·痹论》", "interpretation": "暴饮暴食是肠胃最大的杀手。每餐七分饱，给肠胃留有余地。", "tags": "饮食,肠胃,节制", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 82, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理论", "quote": "五脏所藏：心藏神、肺藏魄、肝藏魂、脾藏意、肾藏志。五脏调和则精神安定。", "source": "《黄帝内经·素问·宣明五气篇》", "interpretation": "心理和精神状态与五脏健康密切相关。养身必须同时养心。", "tags": "五脏,精神,养心", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 83, "figure_id": "sunsimiao", "dimension_id": "shen-ti", "category": "方法", "quote": "养生之道，常欲小劳，但莫大疲，及强所不能堪耳。百病从脚起，脚暖则全身暖。", "source": "《千金要方》", "interpretation": "适度运动、不过度劳累、注意足部保暖——简单但极其有效的养生原则。", "tags": "运动,适度,保暖", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "孙思邈", "dimension_name": "身体健康与养生"}, {"id": 84, "figure_id": "zhangzhongjing", "dimension_id": "shen-ti", "category": "核心理念", "quote": "上以疗君亲之疾，下以救贫贱之厄，中以保身长全。", "source": "《伤寒杂病论·序》", "interpretation": "张仲景写医书的初衷：上为治疗家人疾病，下为救济百姓苦难，中为保养自身健康。三个层次兼顾。", "tags": "医圣,初心,健康", "created_at": "2026-07-04 12:49:25", "updated_at": "2026-07-04 12:49:25", "figure_name": "张仲景", "dimension_name": "身体健康与养生"}, {"id": 85, "figure_id": "franklin", "dimension_id": "xiu-shen", "category": "方法论", "quote": "节制、沉默、秩序、决心、节俭、勤奋、诚实、正义、中庸、整洁、平静、贞洁、谦逊——富兰克林十三条美德", "source": "《富兰克林自传》", "interpretation": "富兰克林的十三条美德是他从20岁开始践行的修身体系。每周专注一项，十三周一个循环，一年循环四次。精髓不在于完美达标，而在于持续自我观察和改进。", "tags": "修身,美德,方法,系统", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "本杰明·富兰克林", "dimension_name": "修身与学习"}, {"id": 86, "figure_id": "franklin", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "早睡早起使人健康、富有、智慧。", "source": "《穷查理年鉴》", "interpretation": "这句箴言被芒格反复引用。作息规律是修身的基础，长期看对人的健康、财富和智慧都有复利效应。", "tags": "作息,健康,复利", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "本杰明·富兰克林", "dimension_name": "修身与学习"}, {"id": 87, "figure_id": "franklin", "dimension_id": "gong-zuo", "category": "方法论", "quote": "时间就是金钱。", "source": "《给商人的忠告》", "interpretation": "富兰克林对时间的管理极为严格，每天排定时间表。拖延是最大的成本，这个道理在任何时代都成立。", "tags": "时间管理,效率,成本", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "本杰明·富兰克林", "dimension_name": "工作方法"}, {"id": 88, "figure_id": "franklin", "dimension_id": "tou-zi", "category": "经典语录", "quote": "省一分钱就是赚一分钱。", "source": "《穷查理年鉴》", "interpretation": "节俭不是吝啬，是对资源的尊重。芒格也说过类似的话——不要过度消费。节俭积累的资本是投资的基础。", "tags": "节俭,积累,投资", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "本杰明·富兰克林", "dimension_name": "投资与理财"}, {"id": 89, "figure_id": "franklin", "dimension_id": "she-jiao", "category": "人生智慧", "quote": "财富不属于拥有它的人，而属于享受它的人。", "source": "《穷查理年鉴》", "interpretation": "真正的富有不是拥有多少钱，而是能否享受生活。这和芒格说的「真正的富有是拥有丰富的内心世界」异曲同工。", "tags": "财富,享受,富有", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "本杰明·富兰克林", "dimension_name": "社交与人脉"}, {"id": 90, "figure_id": "franklin", "dimension_id": "li-xiang", "category": "经典语录", "quote": "没有辛勤的劳动，就没有伟大的成就。", "source": "《富兰克林自传》", "interpretation": "成功的公式很简单：勤奋加方法加坚持。富兰克林从一个印刷工学徒成为科学家、外交家、开国元勋。", "tags": "勤奋,成就,坚持", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "本杰明·富兰克林", "dimension_name": "理想与境界"}, {"id": 91, "figure_id": "zengguofan", "dimension_id": "xiu-shen", "category": "方法论", "quote": "主敬、静坐、早起、读书不二、读史、谨言、养气、保身、日知所亡、月无忘所能、作字、夜不出门。", "source": "曾国藩修身十二条款", "interpretation": "十二条日课从静坐养气到读书读史，从谨言慎行到书法练字。关键是每日践行，不搞突击。", "tags": "修身,日课,持续", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "曾国藩", "dimension_name": "修身与学习"}, {"id": 92, "figure_id": "zengguofan", "dimension_id": "qi-jia", "category": "经典语录", "quote": "天下古今之庸人，皆以一惰字致败；天下古今之才人，皆以一傲字致败。", "source": "《曾国藩家书》", "interpretation": "普通人的失败在于懒惰，有才之人的失败在于骄傲。曾国藩在家书中反复强调戒惰戒傲，既是对自己的要求，也是教育子女的核心。", "tags": "教育,修身,惰傲", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "曾国藩", "dimension_name": "齐家与教育"}, {"id": 93, "figure_id": "zengguofan", "dimension_id": "xiu-shen", "category": "方法论", "quote": "读书可以变换气质。", "source": "《曾国藩家书》", "interpretation": "曾国藩认为读书不只是获取知识，更能从根本上改变一个人的气质。他要求子女读书不求多，但求熟读深思。", "tags": "读书,气质,学习", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "曾国藩", "dimension_name": "修身与学习"}, {"id": 94, "figure_id": "zengguofan", "dimension_id": "ling-dao", "category": "经典语录", "quote": "轻财足以聚人，律己足以服人，量宽足以得人，身先足以率人。", "source": "曾国藩名言", "interpretation": "领导者做到这四点：不吝啬钱财所以能聚拢人才，严于律己所以能让人信服，心胸宽广所以能得人心，身先士卒所以能带领团队。", "tags": "领导力,律己,宽厚", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "曾国藩", "dimension_name": "领导力与管理"}, {"id": 95, "figure_id": "zengguofan", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "吾人只有进德、修业两事靠得住。", "source": "《曾国藩家书》", "interpretation": "人生在世只有两件事真正属于自己：品德提升和本事增长。其他如金钱、地位、名声，都是身外之物。", "tags": "修德,修业,价值", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "曾国藩", "dimension_name": "修身与学习"}, {"id": 96, "figure_id": "zengguofan", "dimension_id": "qi-jia", "category": "人生智慧", "quote": "家败离不得个奢字，人败离不得个逸字，讨人嫌离不得个骄字。", "source": "《曾国藩家书》", "interpretation": "一个家庭衰败开始于奢侈，一个人衰败开始于安逸，被人讨厌开始于骄傲。三字警训：奢、逸、骄。", "tags": "家训,节俭,谦逊", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "曾国藩", "dimension_name": "齐家与教育"}, {"id": 97, "figure_id": "aurelius", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "你无法控制外部事件，但你可以控制你对它们的反应。", "source": "《沉思录》", "interpretation": "斯多葛哲学的核心理念。生活中发生什么不重要，重要的是你怎么看待它。芒格的「双轨分析」也有类似的思想——理性分析之外还要觉察自己的情绪。", "tags": "斯多葛,理性,情绪", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "马可·奥勒留", "dimension_name": "修身与学习"}, {"id": 98, "figure_id": "aurelius", "dimension_id": "li-xiang", "category": "核心思想", "quote": "清晨醒来时告诉自己：今天我会遇到爱管闲事的人、忘恩负义的人、傲慢的人、欺骗的人。他们之所以如此是因为他们不知道善与恶的区别。", "source": "《沉思录》", "interpretation": "奥勒留这个早起仪式很实用——预判今天可能遇到的人和事，做好心理准备，就不会轻易被别人激怒。", "tags": "心态,准备,包容", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "马可·奥勒留", "dimension_name": "理想与境界"}, {"id": 99, "figure_id": "aurelius", "dimension_id": "shen-ti", "category": "人生智慧", "quote": "灵魂比身体更强大。培养你的灵魂，因为它会陪伴你一生。身体只是一个暂时的居所。", "source": "《沉思录》", "interpretation": "身体会衰老，但精神可以不断成长。这和中医「形与神俱」的思想一致——养身的同时必须养心。", "tags": "灵魂,精神,养心", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "马可·奥勒留", "dimension_name": "身体健康与养生"}, {"id": 100, "figure_id": "aurelius", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "生活的艺术更像摔跤而非舞蹈——它要求我们站稳脚跟，随时准备应对突如其来的攻击。", "source": "《沉思录》", "interpretation": "人生不是精心编排的舞蹈，而是一场摔跤。你无法预知下一个回合对手怎么出招，但可以训练自己站稳脚跟。", "tags": "人生智慧,应对,韧性", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "马可·奥勒留", "dimension_name": "修身与学习"}, {"id": 101, "figure_id": "laozi", "dimension_id": "ling-dao", "category": "核心思想", "quote": "上善若水。水善利万物而不争，处众人之所恶，故几于道。", "source": "《道德经》第八章", "interpretation": "最高的善就像水一样滋养万物却不争功，甘居众人不愿处的低位。老子用水来比喻最高级的领导力——不争而胜。", "tags": "领导力,水,不争", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "老子", "dimension_name": "领导力与管理"}, {"id": 102, "figure_id": "laozi", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "知人者智，自知者明。胜人者有力，自胜者强。", "source": "《道德经》第三十三章", "interpretation": "了解别人是聪明，了解自己才是智慧；战胜别人是有力量，战胜自己才是强大。芒格的能力圈理论也是这个道理。", "tags": "自知,自胜,能力圈", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "老子", "dimension_name": "修身与学习"}, {"id": 103, "figure_id": "laozi", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "千里之行，始于足下。", "source": "《道德经》第六十四章", "interpretation": "无论多宏大的事业，都是从脚下第一步开始的。芒格的「每天变聪明一点点」也是这个意思——复利的力量在于持续前进。", "tags": "行动,积累,复利", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "老子", "dimension_name": "修身与学习"}, {"id": 104, "figure_id": "laozi", "dimension_id": "tou-zi", "category": "核心思想", "quote": "大方无隅，大器晚成，大音希声，大象无形。", "source": "《道德经》第四十一章", "interpretation": "最大的方正没有棱角，最大的器物最晚完成。真正的投资也是如此——不做短线套利，长期持有等待大器晚成。这和芒格的「一生只做几个大决策」异曲同工。", "tags": "长期,耐心,大器晚成", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "老子", "dimension_name": "投资与理财"}, {"id": 105, "figure_id": "laozi", "dimension_id": "ling-dao", "category": "核心思想", "quote": "治大国若烹小鲜。", "source": "《道德经》第六十章", "interpretation": "治理大国像烹小鱼——不要频繁翻动，否则鱼会碎。管理也是一样：制度定了就不要朝令夕改，给团队稳定的预期。", "tags": "管理,稳定,预期", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "老子", "dimension_name": "领导力与管理"}, {"id": 106, "figure_id": "laozi", "dimension_id": "li-xiang", "category": "核心思想", "quote": "人法地，地法天，天法道，道法自然。", "source": "《道德经》第二十五章", "interpretation": "人效法地，地效法天，天效法道，道效法自然。最终回归自然——顺应事物本来的规律，不要强求。", "tags": "自然,道,规律", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "老子", "dimension_name": "理想与境界"}, {"id": 107, "figure_id": "kongzi", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "学而不思则罔，思而不学则殆。", "source": "《论语·为政》", "interpretation": "只学习不思考就会迷惘，只思考不学习就会危险。这和芒格的多元思维模型一样——光阅读不行，还要用模型去思考。", "tags": "学习,思考,方法", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孔子", "dimension_name": "修身与学习"}, {"id": 108, "figure_id": "kongzi", "dimension_id": "she-jiao", "category": "经典语录", "quote": "己所不欲，勿施于人。", "source": "《论语·颜渊》", "interpretation": "自己不愿意的事情不要强加给别人。这是孔子「仁」的核心。戈特曼在婚姻研究中发现——用温和的方式沟通本质上就是己所不欲勿施于人。", "tags": "仁,换位思考,关系", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孔子", "dimension_name": "社交与人脉"}, {"id": 109, "figure_id": "kongzi", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "三人行，必有我师焉。择其善者而从之，其不善者而改之。", "source": "《论语·述而》", "interpretation": "一群人一起走，一定有值得我学习的人。好的就学，不好的就反省自己。从一切经验中学习。", "tags": "学习,谦逊,反省", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孔子", "dimension_name": "修身与学习"}, {"id": 110, "figure_id": "kongzi", "dimension_id": "chuang-ye", "category": "经典语录", "quote": "欲速则不达，见小利则大事不成。", "source": "《论语·子路》", "interpretation": "贪图快反而达不到目的，贪图小利就成不了大事。对创业者和投资者来说，这个道理极其重要——耐心和格局是成事的基石。", "tags": "耐心,格局,创业", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孔子", "dimension_name": "创业与事业"}, {"id": 111, "figure_id": "kongzi", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "吾日三省吾身：为人谋而不忠乎？与朋友交而不信乎？传不习乎？", "source": "《论语·学而》", "interpretation": "最朴素的自我反省方法——每天问自己三个问题：替人办事尽力了吗？与朋友交往诚信吗？学到的练习了吗？", "tags": "反省,诚信,实践", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孔子", "dimension_name": "修身与学习"}, {"id": 112, "figure_id": "kongzi", "dimension_id": "qi-jia", "category": "经典语录", "quote": "其身正，不令而行；其身不正，虽令不从。", "source": "《论语·子路》", "interpretation": "领导者自身端正，不下命令下属也会跟着做；自身不端正，命令也没人听从。教育孩子也是如此——身教重于言传。", "tags": "榜样,领导力,身教", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孔子", "dimension_name": "齐家与教育"}, {"id": 113, "figure_id": "wangyangming", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "知是行之始，行是知之成。", "source": "《传习录》", "interpretation": "认知是行动的开始，行动是认知的完成。王阳明反对把知和行分开——光知道不行动等于不知道。这和毛主席的「读书是学习，使用也是学习」完全一致。", "tags": "知行合一,实践,行动", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "王阳明", "dimension_name": "修身与学习"}, {"id": 114, "figure_id": "wangyangming", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "破山中贼易，破心中贼难。", "source": "王阳明名言", "interpretation": "打败山里的贼容易，打败自己内心的贪嗔痴慢疑才难。修身最难的不是外部敌人，而是自己的心。与芒格的误判心理学遥相呼应。", "tags": "内心,修身,自省", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "王阳明", "dimension_name": "修身与学习"}, {"id": 115, "figure_id": "wangyangming", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "心即理。天下又有心外之事，心外之理乎？", "source": "《传习录》", "interpretation": "心就是道理所在。天下没有心外的事物，也没有心外的道理。求理不用外求，向内探索自己就够了。", "tags": "心学,内求,致知", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "王阳明", "dimension_name": "修身与学习"}, {"id": 116, "figure_id": "wangyangming", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "致良知。", "source": "王阳明心学核心", "interpretation": "每个人内心都有良知，知道自己该怎么做。修身的要义就是真诚地听从良知的指引，把它付诸行动。", "tags": "良知,修身,真诚", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "王阳明", "dimension_name": "修身与学习"}, {"id": 117, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "亲密关系中的承诺有三种类型：个人承诺（我想留下）、强迫承诺（我不得不留下）、道德承诺（我应该留下）。最稳固的是三者兼备。", "source": "《亲密关系》", "interpretation": "不仅问自己「我还爱不爱TA」，也问「我是否愿意为这段关系负责」。承诺不只是感觉，更是一种选择。", "tags": "承诺,关系,稳固", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 118, "figure_id": "gottman", "dimension_id": "hun-yin", "category": "方法", "quote": "婚姻修复的第一步不是解决问题，而是先做情感连接。配偶向你抱怨时，TA真正想要的是被理解和重视。", "source": "《幸福的婚姻》", "interpretation": "当伴侣抱怨时，先别急着解释或反驳。先回应情感——「我理解你的感受」「这件事对你很重要」，冲突往往就消解了一半。", "tags": "情感连接,倾听,修复", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "约翰·戈特曼", "dimension_name": "婚姻与亲密关系"}, {"id": 119, "figure_id": "chapman", "dimension_id": "hun-yin", "category": "方法", "quote": "如果你不知道对方的主要爱语是什么，可以观察TA最常向你提出什么要求，或TA最常抱怨你什么。", "source": "《爱的五种语言》", "interpretation": "抱怨往往是爱的语言的反面指标：「你从来不陪我」说明精心的时刻是TA的语言；「你从来不说爱我」说明肯定的言辞是TA的语言。", "tags": "爱的语言,观察,理解", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "盖瑞·查普曼", "dimension_name": "婚姻与亲密关系"}, {"id": 120, "figure_id": "montessori", "dimension_id": "qi-jia", "category": "方法", "quote": "儿童的工作和成人的工作不同：成人工作是为了结果，儿童工作是为了发展自身。因此不要用效率来评价孩子的活动。", "source": "蒙特梭利教育法", "interpretation": "孩子反复做一件事在成人看来是浪费时间，但这是他在建构自己的心智。允许孩子慢慢来，就是给他成长的空间。", "tags": "儿童,工作,发展", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "玛丽亚·蒙特梭利", "dimension_name": "齐家与教育"}, {"id": 121, "figure_id": "nelsen", "dimension_id": "qi-jia", "category": "方法", "quote": "惩罚的四个后果：愤恨、报复、反叛、退缩。正面管教的核心是用长期有效的教育方式替代惩罚。", "source": "《正面管教》", "interpretation": "惩罚看起来立竿见影，但长期代价巨大。问问自己：我现在做的，是在培养孩子的自律，还是只是在追求表面的服从？", "tags": "惩罚,正面管教,自律", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "简·尼尔森", "dimension_name": "齐家与教育"}, {"id": 122, "figure_id": "vygotsky", "dimension_id": "qi-jia", "category": "核心理论", "quote": "儿童在合作中能比独立完成更多。今天在成人帮助下能做的事，明天他就能独立完成。", "source": "最近发展区理论", "interpretation": "你不是替孩子做事，也不是让他自己硬扛。在他的能力边沿提供恰到好处的帮助——这就是教育的艺术。", "tags": "最近发展区,合作,指导", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "列夫·维果茨基", "dimension_name": "齐家与教育"}, {"id": 123, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理念", "quote": "恬淡虚无，真气从之，精神内守，病安从来。", "source": "《黄帝内经·素问·上古天真论》", "interpretation": "内心保持恬静淡泊，正气自然旺盛。精神守住不外耗，疾病从哪里来呢？这是养生的最高境界——养心为要。", "tags": "养心,精神,静养", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 124, "figure_id": "huangdi", "dimension_id": "shen-ti", "category": "核心理念", "quote": "久视伤血，久卧伤气，久坐伤肉，久立伤骨，久行伤筋。是谓五劳所伤。", "source": "《黄帝内经·素问·宣明五气篇》", "interpretation": "任何事情过度都会伤身。现代人最常见的「久视」（看屏幕）和「久坐」正好对应伤血和伤肉。定时起身活动、减少屏幕时间是最简单的养生。", "tags": "五劳,过度,现代病", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "黄帝内经", "dimension_name": "身体健康与养生"}, {"id": 125, "figure_id": "sunsimiao", "dimension_id": "shen-ti", "category": "方法", "quote": "善养性者，则治未病之病，是其义也。", "source": "《千金要方·养性序》", "interpretation": "善于养生的人，在病还没发生的时候就预防了。孙思邈这套思想和黄帝内经「上工治未病」一脉相承——最好的治疗是预防。", "tags": "治未病,预防,养生", "created_at": "2026-07-04 13:17:48", "updated_at": "2026-07-04 13:17:48", "figure_name": "孙思邈", "dimension_name": "身体健康与养生"}, {"id": 126, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "调查就像十月怀胎，解决问题就像一朝分娩。调查就是解决问题。", "source": "《反对本本主义》1930", "interpretation": "毛泽东把调查比作怀孕——急不得。很多人想跳过调查直接找答案，这就像想跳过怀孕直接生孩子。充分的调查自然引出解决方案。", "tags": "调查,方法,创业", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 127, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "调查的技术：要开调查会、要深入群众、要自己做记录、要讨论式的调查、要定调查纲目。", "source": "《反对本本主义》1930", "interpretation": "这套调查方法放到今天依然实用：不要只看二手数据、不要只发问卷、要和真正在一线的人面对面交流。开个小座谈会比看一百份报告更有用。", "tags": "调查,方法,技术", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 128, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "你对于某个问题没有调查，就停止你对于某个问题的发言权。", "source": "《反对本本主义》1930", "interpretation": "这条原则在投资中极其重要——没研究透的公司就不要碰。芒格的能力圈也是这个意思。", "tags": "调查,发言权,能力圈", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 129, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "战争的过程分为三个阶段：战略防御、战略相持、战略反攻。", "source": "《论持久战》1938", "interpretation": "创业也可以用这个框架：早期活下来（防御）、中期建立优势（相持）、后期规模化扩张（反攻）。大多数创业者在相持阶段就放弃了。", "tags": "战略,创业,持久战", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 130, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "主动性、灵活性、计划性——这是战争指导的三个基本原则。", "source": "《论持久战》1938", "interpretation": "创业也是这三条：主动把握局势（不要被对手牵着走）、灵活调整策略（不要死守原计划）、有计划有步骤地推进（不要东一榔头西一棒子）。", "tags": "战略,创业,三性", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 131, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "凡事预则立，不预则废。没有事先的计划和准备，就不能获得战争的胜利。", "source": "《论持久战》1938", "interpretation": "不管做什么事，有准备比没准备好。投资要有投资计划，创业要有商业计划，学习要有学习计划。计划不一定全对，但有计划比没计划强百倍。", "tags": "计划,准备,工作方法", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 132, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "战略上藐视敌人，战术上重视敌人。", "source": "《论持久战》1938", "interpretation": "对待困难的正确态度：在整体上不怕它（藐视），在具体操作上认真对待它（重视）。投资时长期看多中国（战略藐视），但每笔投资决策都要谨慎（战术重视）。", "tags": "战略,战术,心态", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 133, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "方法论", "quote": "自由主义有十一种表现：不做具体工作、说了不做、明知不对不批评、工作不认真、命令不执行、不联系群众、损害组织利益、自由放任、消极怠工、工作挑拣、缺乏纪律。", "source": "《反对自由主义》1937", "interpretation": "这十一种自由主义表现放到职场中依然普遍。每周对照自查一次，能发现自己很多不经意的习惯性错误。这也是芒格说的「反过来想」——避免这些行为，就能变得更好。", "tags": "自由主义,自省,态度", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 134, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "自由主义是机会主义的一种表现，是和马克思主义根本冲突的。", "source": "《反对自由主义》1937", "interpretation": "自由主义本质上是对自己放松要求。对自己高标准的人，不会允许自己「差不多就行」。这和曾国藩的「戒惰戒傲」是一个道理。", "tags": "自律,标准,态度", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 135, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "方法论", "quote": "改造我们的学习，要注重研究历史、研究现状、研究理论，把理论和实际统一起来。", "source": "《改造我们的学习》1941", "interpretation": "学习的三条路径：研究现状（知道现在发生了什么）、研究历史（知道过去是怎么来的）、研究理论（知道背后的原理）。三条缺一不可。", "tags": "学习,方法,理论实际", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 136, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "没有科学的态度，即没有马克思列宁主义的理论和实践统一的态度，就叫做没有党性。", "source": "《改造我们的学习》1941", "interpretation": "所谓科学态度就是实事求是，就是理论和实际统一。学了一个理论不去验证、不联系实际，就等于没学。", "tags": "科学态度,实事求是,学习", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 137, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "从群众中来，到群众中去。将群众的意见集中起来，又到群众中去宣传解释，化为群众的意见，使群众坚持下去见之于行动。", "source": "《关于领导方法的若干问题》1943", "interpretation": "决策流程：收集一线意见（从群众中来）→ 分析加工形成决策（集中起来）→ 回到一线执行验证（到群众中去）。循环往复，一次比一次更正确。", "tags": "群众路线,决策,执行", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 138, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "一般号召和个别指导相结合。没有一般号召就不能动员群众，但光有一般号召没有具体指导就会落空。", "source": "《关于领导方法的若干问题》1943", "interpretation": "管理时既要定方向（一般号召），也要抓落地（个别指导）。只喊口号不抓落实是空谈，只陷在细节没有方向是盲目。", "tags": "领导力,方法,执行", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 139, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "领导骨干和广大群众相结合。只有领导骨干的积极性而无广大群众的积极性结合，便将成为少数人的空忙。", "source": "《关于领导方法的若干问题》1943", "interpretation": "管理者不能自己闷头干。要发动团队一起干。光自己忙是无效的，让大家都朝一个方向努力才是领导力。", "tags": "领导力,团队,发动", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 140, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "党委书记要善于当班长。要把问题摆到桌面上来。互通情报。不懂得和不了解的东西要问下级。学会弹钢琴。要抓紧。胸中有数。", "source": "《党委会的工作方法》1949", "interpretation": "十二条工作方法精华：公开透明、信息互通、不懂就问、统筹兼顾、抓紧重点、心中有数。每一条都是实用的管理技巧。", "tags": "领导力,工作方法,十二条", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 141, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "学会弹钢琴。弹钢琴要十个指头都动作，但不能有的按有的不按。要产生好的音乐，十个指头的动作要有节奏、互相配合。", "source": "《党委会的工作方法》1949", "interpretation": "管理也要学会弹钢琴——各项工作都要兼顾，但有主次、有节奏。不能只顾一点不管其他，也不能平均用力没有重点。", "tags": "管理,统筹,节奏", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 142, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "要抓紧。就是说，对主要工作不但一定要抓，而且一定要抓紧。什么东西只有抓得很紧，毫不放松，才能抓住。抓而不紧，等于不抓。", "source": "《党委会的工作方法》1949", "interpretation": "定了重要的事就要一抓到底，不能半途而废。很多人定了目标但没坚持到底，就是「抓而不紧，等于不抓」。", "tags": "执行,坚持,落实", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 143, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "人总是要死的，但死的意义有不同。为人民利益而死，就比泰山还重；替法西斯卖力，替剥削人民和压迫人民的人去死，就比鸿毛还轻。", "source": "《为人民服务》1944", "interpretation": "人生的价值不在于活了多久，而在于为谁而活、做了什么。这句话虽然带有时代背景，但核心思想是超越时代的——找到比自己更大的意义。", "tags": "价值,意义,奉献", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 144, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "因为我们是为人民服务的，所以，我们如果有缺点，就不怕别人批评指出。不管是什么人，谁向我们指出都行。只要你说得对，我们就改正。", "source": "《为人民服务》1944", "interpretation": "真正自信的人不怕批评。好的建议不管来自哪里都应该接受。这和芒格的「红队演练」异曲同工——请人来反对自己。", "tags": "批评,改进,开放", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 145, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "下定决心，不怕牺牲，排除万难，去争取胜利。", "source": "《愚公移山》1945", "interpretation": "持久战精神的最佳表达。定下目标就不要轻易放弃。创业路上会遇到无数次困难，这句话是很好的心理建设——只要方向对，坚持就是胜利。", "tags": "坚持,决心,信念", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 146, "figure_id": "mao", "dimension_id": "li-xiang", "category": "核心思想", "quote": "愚公移山的故事告诉我们：山不会变大，但挖山的人可以一代接一代。只要坚持下去，就没有移不了的山。", "source": "《愚公移山》1945", "interpretation": "复利思维在行动上的体现。每天搬一点石头，山总会挖完的。芒格也说「每天变聪明一点，到最后你会得到你应得的」。", "tags": "坚持,复利,行动", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 147, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "方法论", "quote": "反对主观主义以整顿学风、反对宗派主义以整顿党风、反对党八股以整顿文风。", "source": "《整顿党的作风》1942", "interpretation": "三个反对放在今天依然成立：不要凭主观臆断做事（主观主义）、不要拉帮结派（宗派主义）、不要说空话套话（党八股）。和人相处也是如此。", "tags": "作风,学风,党风", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 148, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "白求恩同志毫不利己专门利人的精神，表现在他对工作的极端的负责任，对同志对人民的极端的热忱。", "source": "《纪念白求恩》1939", "interpretation": "两个极端：极端负责任、极端热忱。做事的态度就这两种：要么不做，做就做到极致。", "tags": "责任,热忱,态度", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 149, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "一个人能力有大小，但只要有这点精神，就是一个高尚的人，一个纯粹的人，一个有道德的人，一个脱离了低级趣味的人，一个有益于人民的人。", "source": "《纪念白求恩》1939", "interpretation": "这是毛泽东对人格的最高期许。能力可以不同，但精神境界是每个人都应该追求的。芒格也说「理性是一种道德责任」。", "tags": "人格,境界,道德", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 150, "figure_id": "mao", "dimension_id": "li-xiang", "category": "核心思想", "quote": "所谓革命高潮快要到来，绝不是如有些人所谓「有到来之可能」那样完全没有行动意义的、可望而不可即的一种空的东西。它是站在海岸遥望海中已经看得见桅杆尖头了的一只航船。", "source": "《星星之火，可以燎原》1930", "interpretation": "看形势要有辩证眼光：在最黑暗的时候看到希望。创业和投资中，能在大家悲观时看到机会的苗头，是一种宝贵的判断力。", "tags": "信念,希望,判断力", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 151, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "战略退却是为了保存军力，准备反攻。退却阶段要选择有利于我的阵地，造成有利于我的条件。", "source": "《中国革命战争的战略问题》1936", "interpretation": "创业中的战略退却不是失败，而是主动收缩。当市场环境不好时，主动收缩、保存实力、等待时机，是明智的选择。", "tags": "战略,退却,创业", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 152, "figure_id": "mao", "dimension_id": "tou-zi", "category": "核心思想", "quote": "战略反攻阶段，要集中兵力，打歼灭战而不是击溃战。伤其十指不如断其一指。", "source": "《中国革命战争的战略问题》1936", "interpretation": "投资也是一样：与其分散投十个项目每个都小赚一点，不如集中火力重仓自己最看好的那个。伤其十指不如断其一指。", "tags": "投资,聚焦,集中", "created_at": "2026-07-04 13:51:48", "updated_at": "2026-07-04 13:51:48", "figure_name": "毛泽东", "dimension_name": "投资与理财"}, {"id": 153, "figure_id": "mao", "dimension_id": "she-jiao", "category": "方法论", "quote": "谁是我们的敌人？谁是我们的朋友？这个问题是革命的首要问题。", "source": "《中国社会各阶级的分析》1925", "interpretation": "做任何事情之前，首先要搞清楚利益相关方——谁是支持你的、谁是反对你的、谁是可以争取的。创业时先分清楚：用户、竞争对手、合作伙伴、监管者，各自立场是什么？", "tags": "分析,利益相关方,方法", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "社交与人脉"}, {"id": 154, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "方法论", "quote": "我们要分辨真正的敌友，不可不将中国社会各阶级的经济地位及其对于革命的态度，做一个大概的分析。", "source": "《中国社会各阶级的分析》1925", "interpretation": "分析问题的框架：从经济地位（利益立场）出发，推断其对事情的态度。在商业中同理——分析一个公司，先看它的商业模式和利益驱动。", "tags": "分析,阶级,商业", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 155, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "方法论", "quote": "农民的主要攻击目标是土豪劣绅、不法地主，旁及各种宗法的思想和制度，城里的贪官污吏，乡村的恶劣习惯。这个攻击的形势，简直是急风暴雨，顺之者存，违之者灭。", "source": "《湖南农民运动考察报告》1927", "interpretation": "这篇报告是毛泽东花了32天实地调研写成的。他用大量第一手案例证明了调查的价值。好的调研报告不是罗列数据，而是用具体案例说明趋势。", "tags": "调查,案例,方法", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 156, "figure_id": "mao", "dimension_id": "gong-zuo", "category": "经典语录", "quote": "没有调查的发言权——不是没有发言权，而是去调查了才有。", "source": "《湖南农民运动考察报告》1927", "interpretation": "这篇报告的底稿来自实地走访——和农民一起吃饭、聊天、开会。真正的调研不是发问卷，而是到现场去。", "tags": "调查,实地,方法", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "工作方法"}, {"id": 157, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "单纯军事观点：认为军事和政治是对立的，军事好政治自然好。这种思想如果发展下去，便有走到脱离群众、以军队控制政权的危险。", "source": "《关于纠正党内的错误思想》1929", "interpretation": "团队管理中常见的错误：只抓业务不抓文化，认为业绩好一切自然好。实际上业绩好和团队建设要并重。", "tags": "管理,团队,文化", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 158, "figure_id": "mao", "dimension_id": "ling-dao", "category": "方法论", "quote": "极端民主化：要求实行所谓「由下而上的民主集权制」，先交下级讨论，再由上级决议。这种思想是极端民主化的错误倾向。", "source": "《关于纠正党内的错误思想》1929", "interpretation": "管理中不能什么都民主讨论。关键决策要果断，日常事务可民主。什么事都开会讨论会陷入效率陷阱。", "tags": "管理,决策,民主", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "领导力与管理"}, {"id": 159, "figure_id": "mao", "dimension_id": "she-jiao", "category": "方法论", "quote": "我们的方针是统一战线中的独立自主，既统一又独立。", "source": "《统一战线中的独立自主问题》1938", "interpretation": "合作中要保持自己的独立性。既不能因为合作而丧失自我，也不能因为独立而不合作。商业合作中也是如此——共赢但不丧失主导权。", "tags": "合作,独立,策略", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "社交与人脉"}, {"id": 160, "figure_id": "mao", "dimension_id": "li-xiang", "category": "经典语录", "quote": "一切反动派都是纸老虎。看起来反动派的样子是可怕的，但是实际上并没有什么了不起的力量。", "source": "《和美国记者安娜·路易斯·斯特朗的谈话》1946", "interpretation": "战略上藐视对手——看起来很强大的对手往往有内在的弱点。投资中看到的利空消息，仔细分析可能没那么可怕。关键在于区分表面实力和真实实力。", "tags": "战略,藐视,信念", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "理想与境界"}, {"id": 161, "figure_id": "mao", "dimension_id": "chuang-ye", "category": "方法论", "quote": "不打无准备之仗，不打无把握之仗。每战都应力求有准备，力求在敌我条件对比下有胜利的把握。", "source": "《目前形势和我们的任务》1947", "interpretation": "重复强调：有准备再出手。创业不是赌运气，是要在充分准备的基础上行动。准备到什么程度？到你有七八成把握。", "tags": "准备,把握,创业", "created_at": "2026-07-04 13:55:23", "updated_at": "2026-07-04 13:55:23", "figure_name": "毛泽东", "dimension_name": "创业与事业"}, {"id": 162, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "马克思主义的哲学辩证唯物论有两个最显著的特点：一个是它的阶级性，公然申明辩证唯物论是为无产阶级服务的；再一个是它的实践性，强调理论对于实践的依赖关系，理论的基础是实践，又转过来为实践服务。", "source": "《实践论》1937", "interpretation": "两个特点：阶级性（立场）和实践性（方法）。对普通人来说，实践性更有启发——任何理论的价值都要通过实践来验证。脱离实践的理论是空洞的理论。", "tags": "实践,理论,马克思", "created_at": "2026-07-04 13:56:10", "updated_at": "2026-07-04 13:56:10", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 163, "figure_id": "mao", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "事物发展的根本原因，不是在事物的外部而是在事物的内部，在于事物内部的矛盾性。", "source": "《矛盾论》1937", "interpretation": "分析问题要从内部找原因，而不是归咎于外部。公司出了问题先看内部管理和产品，而不是怪市场不好。内因是变化的根据，外因是变化的条件。", "tags": "矛盾,内因,分析", "created_at": "2026-07-04 13:56:10", "updated_at": "2026-07-04 13:56:10", "figure_name": "毛泽东", "dimension_name": "修身与学习"}, {"id": 164, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "人们带着既有的信念和期望进入关系，这些信念会影响我们如何解读伴侣的行为。关系信念分为两类：成长信念（关系可以改善）和宿命信念（关系要么合适要么不合适）。", "source": "《亲密关系》第4章", "interpretation": "持有成长信念的人更愿意为关系投入努力，遇到问题时积极解决；持有宿命信念的人遇到困难容易放弃。检查自己的关系信念——你相信关系能变得更好吗？", "tags": "社会认知,信念,成长", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 165, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "在亲密关系中，我们常常高估自己的贡献而低估伴侣的贡献。这种自我服务偏差是关系冲突的重要来源。", "source": "《亲密关系》第4章", "interpretation": "当你们在争论谁付出更多时，提醒自己：我们都倾向于高估自己的付出。主动承认对方的付出是化解这种偏差的第一步。", "tags": "认知偏差,自我服务,冲突", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 166, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "我们对伴侣行为的归因方式直接影响关系满意度。幸福夫妻倾向于把伴侣的正面行为归因为内在特质（TA本来就是个好人），把负面行为归因为外部因素（TA今天太累了）。", "source": "《亲密关系》第4章", "interpretation": "不幸福夫妻的归因方式正好相反：把好的归因于运气，把坏的归因于人品。改变归因方式就能改变关系感受。", "tags": "归因,认知,满意度", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 167, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "沟通中的「要求/退避模式」是关系破坏力最强的模式之一：一方不断提出要求，另一方不断退避回避。这个模式一旦形成就会自我强化。", "source": "《亲密关系》第5章", "interpretation": "如果你在关系中总是追、对方总是逃，需要意识到这是两个人的互动模式问题，不只是对方的错。打破这个模式需要双方意识到并主动调整。", "tags": "沟通,模式,要求退避", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 168, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "良好的沟通不在于没有误解，而在于能及时修复误解。成功的修复尝试是高质量关系的关键标志。", "source": "《亲密关系》第5章", "interpretation": "吵架后主动示好、道歉、或幽默化解都是修复尝试。重要的是对方能识别并接受这种尝试。", "tags": "沟通,修复,误解", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 169, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "友谊的核心特征是：自愿、平等、互助、享受彼此的陪伴。友谊的质量比数量更重要——有几个知己比有一百个熟人更有益于健康。", "source": "《亲密关系》第7章", "interpretation": "成年后友谊最难的是维持联系。定期主动联系、在对方需要时出现、不做评价地倾听，这些都是好朋友的标志。", "tags": "友谊,质量,维系", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 170, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "男女友谊的最大挑战是「性吸引力的干扰」。纯友谊需要双方都明确这是友谊而非暧昧，并尊重彼此的边界。", "source": "《亲密关系》第7章", "interpretation": "异性友谊可以存在，但需要双方对关系的性质有共识。模糊不清的边界是友谊破裂最常见的原因。", "tags": "友谊,边界,异性", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 171, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "斯滕伯格的爱情三角理论：完美的爱情由亲密（情感连接）、激情（身体吸引）、承诺（决定维持）三个成分构成。只有三个都具备才是圆满的爱情。", "source": "《亲密关系》第8章", "interpretation": "热恋期充满激情但承诺尚未建立；长期婚姻中激情消退但亲密和承诺仍在。不同阶段的爱情形态不同，关键是要识别缺了什么成分。", "tags": "爱情三角,亲密,激情,承诺", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 172, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "爱情不是一种，而是多种。分为：浪漫之爱（亲密+激情）、相伴之爱（亲密+承诺）、愚昧之爱（激情+承诺）、圆满之爱（三者兼备）。", "source": "《亲密关系》第8章", "interpretation": "你的关系属于哪种类型？缺了什么？意识到缺什么就能有针对性地改善。长期的婚姻更像是相伴之爱——不是不浪漫，而是浪漫的形态变了。", "tags": "爱情类型,浪漫,相伴", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 173, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "性亲密和关系满意度是相互促进的：关系越好性越满意，性越满意关系越好。但性本身不能拯救一段已经破裂的关系。", "source": "《亲密关系》第9章", "interpretation": "性只是关系的一面镜子——好的关系通常有好的性生活，但改善性本身并不能改善关系。先改善关系，性自然会改善。", "tags": "性亲密,满意度,关系", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 174, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "伴侣间的性欲望差异（性欲不匹配）是常见的冲突来源。差异本身不是问题，如何处理差异才是。", "source": "《亲密关系》第9章", "interpretation": "性欲不匹配几乎存在于所有长期关系中。处理方式：沟通不评判、寻找双方都能接受的频率、不要把拒绝当作对个人的否定。", "tags": "性欲,差异,沟通", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 175, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "嫉妒分为反应性嫉妒（伴侣真的出轨了）和怀疑性嫉妒（只是怀疑）。过度的嫉妒会损害关系，因为嫉妒会引发控制行为，控制行为会破坏信任。", "source": "《亲密关系》第10章", "interpretation": "适度的嫉妒是正常的，但过度嫉妒会变成自我实现的预言——你越害怕对方离开，你的行为越可能把对方推开。", "tags": "嫉妒,信任,控制", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 176, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "关系中的欺骗分为两种：一种是善意的谎言（为了不伤害对方），一种是利己的欺骗（为了自己获益）。前者在适度范围内不影响关系，后者是关系的大敌。", "source": "《亲密关系》第10章", "interpretation": "完全没有秘密的关系不一定是健康的关系。关键在于你欺骗的动机是保护对方还是保护自己。", "tags": "欺骗,信任,诚实", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 177, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "冲突是不可避免的，但冲突本身不破坏关系——处理冲突的方式才重要。建设性的冲突可以增强关系，破坏性的冲突才损害关系。", "source": "《亲密关系》第11章", "interpretation": "从不吵架的夫妻不一定幸福，可能是回避了所有冲突。学会有建设性地吵架，比不吵架更重要。", "tags": "冲突,建设性,关系", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 178, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "冲突解决四步法：冷静下来→换位思考→表达感受而非指责→寻找共同接受的解决方案。", "source": "《亲密关系》第11章", "interpretation": "下次吵架时试试：先暂停10分钟让情绪平复，然后用第一人称表达感受。这个简单的流程能避免90%的破坏性冲突。", "tags": "冲突解决,方法,沟通", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 179, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "亲密关系中的权力不是固定的——谁拥有更多资源（经济、社交、情感）谁就拥有更多权力。但健康的长期关系应该是权力共享的。", "source": "《亲密关系》第12章", "interpretation": "经济独立是关系中的底气。不健康的关系中，一方利用经济或情感资源控制另一方。识别权力不平衡是改善关系的第一步。", "tags": "权力,平衡,独立", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 180, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "关系解体通常经历五个阶段：不满→讨论→决定→分离→结束。大多数人在第一阶段停留太久——不满积累到爆发时已经无法挽回了。", "source": "《亲密关系》第13章", "interpretation": "如果你感到不满，不要等到无法忍受再说。尽早沟通、尽早采取行动。大多数关系不是死于重大冲突，而是死于日常的忽视。", "tags": "解体,阶段,预防", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 181, "figure_id": "miller", "dimension_id": "hun-yin", "category": "核心理论", "quote": "分手后的恢复过程不是线性的，而是螺旋上升。可能会有反复——今天觉得好了，明天又崩溃了。这是正常的。", "source": "《亲密关系》第13章", "interpretation": "分手后允许自己悲伤。研究显示，那些允许自己完全体验分手痛苦的人，反而恢复得更快。", "tags": "分手,恢复,悲伤", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 182, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "关系维持策略有五种：积极性（保持乐观愉快）、开放性（自我表露分享）、保证（强调对关系的承诺）、社交网络（共同的朋友圈）、共享任务（分担家务和责任）。", "source": "《亲密关系》第14章", "interpretation": "这五种策略中，保证和开放性对关系满意度影响最大。定期向伴侣表达你有多重视TA、分享你的内心世界。", "tags": "维持策略,承诺,开放", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 183, "figure_id": "miller", "dimension_id": "hun-yin", "category": "方法", "quote": "幸福的亲密关系不是没有问题，而是有足够多的积极互动来抵消那些不可避免的消极互动。戈特曼的5:1比率在此验证。", "source": "《亲密关系》第14章", "interpretation": "每天刻意做一些小事情：一个拥抱、一句谢谢、一次真诚的夸奖。这些微小但持续的积极互动是关系长久的基石。", "tags": "积极互动,日常,维持", "created_at": "2026-07-04 14:13:07", "updated_at": "2026-07-04 14:13:07", "figure_name": "罗兰·米勒", "dimension_name": "婚姻与亲密关系"}, {"id": 184, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "你必须知道重要学科的重要理论，并经常使用它们——不是只用几种，而是要全部用上。", "source": "《穷查理宝典》第1讲", "interpretation": "不是让你成为每个领域的专家，而是掌握每个学科最核心的思维模型。", "tags": "多元思维,跨学科,格栅理论", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 185, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "方法论", "quote": "最好的学习方法不是读100本书，而是把几本最好的书读100遍。反复读，直到那些思想成为你的一部分。", "source": "《穷查理宝典》第1讲", "interpretation": "芒格推崇深度阅读。深读一本好书胜过泛读十本。", "tags": "阅读,深度学习,方法", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 186, "figure_id": "munger", "dimension_id": "tou-zi", "category": "核心思想", "quote": "Lollapalooza效应——多个因素同向叠加，会产生极端效果。你要寻找那种多个力量同时起作用的情况。", "source": "《穷查理宝典》第2讲", "interpretation": "当激励机制、社会认同、权威等多个因素指向同一方向时，产生1+1大于11的效果。", "tags": "Lollapalooza,叠加,极致", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 187, "figure_id": "munger", "dimension_id": "tou-zi", "category": "方法论", "quote": "投资原则检查清单：风险、独立、准备、谦虚、严格分析、配置、耐心、决心。", "source": "《穷查理宝典》第4讲", "interpretation": "重大决策前走一遍检查清单，可以避免情绪和偏误下的冲动决定。", "tags": "检查清单,投资,决策", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 188, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "好生意的护城河要宽。护城河可以是品牌、规模优势、网络效应、专利或特许经营权。", "source": "《穷查理宝典》第4讲", "interpretation": "没有护城河的生意，迟早会被竞争对手侵蚀掉利润。", "tags": "护城河,竞争优势,长期", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 189, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "优秀的公司有三个特征：能产生自由现金流、有可持续的竞争优势、有优秀的管理层。", "source": "《穷查理宝典》第4讲", "interpretation": "三要素：现金流说明盈利能力，护城河说明可持续性，管理层说明未来。", "tags": "选股,基本面,标准", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 190, "figure_id": "munger", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "伟大的企业需要护城河持续加宽。如果你找不到一个有宽阔护城河的企业，那就囤积现金，等待机会。", "source": "《穷查理宝典》第4讲", "interpretation": "对创业者的启示：找一个有壁垒的细分领域深耕，而不是在红海里拼价格。", "tags": "护城河,创业,壁垒", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "创业与事业"}, {"id": 191, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "方法论", "quote": "每天早上起来，想想今天能做的几件有意义的事。一天结束的时候，看看完成了什么。", "source": "《穷查理宝典》最后一讲", "interpretation": "看似简单，但坚持做几十年就产生了巨大的复利效果。和曾国藩的日课本质相同。", "tags": "日常,自我管理,复利", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 192, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "四十岁以前没有真正的价值投资者。", "source": "《穷查理宝典》", "interpretation": "芒格的意思是：价值投资需要人生阅历和认知深度才能掌握。学方法论容易，学耐心和判断力需要时间。", "tags": "价值投资,阅历,耐心", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 193, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "安全边际——以低于内在价值的价格买入。价格是你付出的，价值是你得到的。", "source": "《穷查理宝典》第4讲", "interpretation": "花80块买值100块的东西，比花95块买值100块的东西安全得多。", "tags": "安全边际,估值,价值", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 194, "figure_id": "munger", "dimension_id": "chuang-ye", "category": "核心思想", "quote": "用多元思维模型分析一个生意的完整方法。从品牌、渠道、配方、规模效应、文化等多个角度同时分析。", "source": "《穷查理宝典》第5讲 可口可乐案例", "interpretation": "芒格用可口可乐展示了如何多角度分析：化学（配方）、心理学（口味偏好）、经济学（规模效应）。", "tags": "多元思维,案例,可口可乐", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "创业与事业"}, {"id": 195, "figure_id": "munger", "dimension_id": "she-jiao", "category": "人生智慧", "quote": "不要和猪摔跤，你们两个都会被泥弄脏，而猪喜欢泥。", "source": "芒格名言", "interpretation": "不要和低质量的人纠缠。选对人比纠正人重要。", "tags": "社交,选择,智慧", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "社交与人脉"}, {"id": 196, "figure_id": "munger", "dimension_id": "ling-dao", "category": "方法论", "quote": "激励机制是超级强大的力量。如果你想让人们做什么，就给他们相应的激励。", "source": "《穷查理宝典》第9讲", "interpretation": "管理、创业、投资中都要思考：这个机制在激励什么行为？有没有激励错方向？", "tags": "激励机制,管理,行为", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "领导力与管理"}, {"id": 197, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "方法论", "quote": "减少错误的最好方法是从别人的错误中学习。聪明人从自己的错误中学习，智慧的人从别人的错误中学习。", "source": "《穷查理宝典》第10讲", "interpretation": "芒格一生都在收集和分析各种失败案例，建立了一个失败清单用来避免犯相同的错。", "tags": "学习,错误,智慧", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 198, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "你不需要在每个机会上都赚钱。你只需要在少数几个机会上赚大钱。", "source": "《穷查理宝典》第4讲", "interpretation": "芒格和巴菲特一生中最重要的10个投资决策，几乎占了伯克希尔总收益的90%以上。", "tags": "集中投资,机会,重仓", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 199, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "遇到问题，先把它简化成你能力圈内的几个核心变量。", "source": "《穷查理宝典》第1讲", "interpretation": "芒格对付复杂性的方法：不是变得更聪明，而是把问题简化到可以理解的范围内。", "tags": "简化,核心变量,分析", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 200, "figure_id": "munger", "dimension_id": "li-xiang", "category": "经典语录", "quote": "人生就像投资一样，你不需要在所有事情上都做对。你只需要在关键的几件事上做对就够了。", "source": "《穷查理宝典》", "interpretation": "婚姻、职业选择、重大投资等少数几个决策，几乎决定了人生的全部。", "tags": "人生,关键决策,选择", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 201, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "聪明人在下结论的时候，总是先找反面证据。愚蠢的人在下结论的时候，总是只找支持自己观点的证据。", "source": "《穷查理宝典》第10讲", "interpretation": "主动寻找反面证据，芒格称之为红队演练——找人来挑战自己的观点。", "tags": "反面证据,红队,决策", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 202, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "如果你想要说服别人，要诉诸利益，而非诉诸理性。", "source": "《穷查理宝典》误判心理学", "interpretation": "激励是世界上最强大的力量。想说服一个人，不要跟他讲道理，跟他讲利益。", "tags": "激励机制,说服,利益", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 203, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "核心思想", "quote": "你必须拥有多元思维模型，因为这些模型能给你提供不同的视角。如果你只有一两个模型，你的人生将非常扭曲。", "source": "《穷查理宝典》第1讲", "interpretation": "模型的多样性决定了你认知的宽度。单一看问题的方式是认知扭曲的根源。", "tags": "多元思维,认知,模型", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 204, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "等待是投资的一部分。大多数时候你什么都不应该做，坐在那里等着就好。", "source": "《穷查理宝典》第4讲", "interpretation": "芒格说：投资的大部分时间应该是等待。不是频繁行动，而是耐心等待最好的机会出现。", "tags": "耐心,等待,长期", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 205, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "建立一个决策检查清单。在你做重大决策之前，逐项核对。这可以避免99%的低级错误。", "source": "《穷查理宝典》第4讲", "interpretation": "检查清单是芒格从飞行员那里学来的方法。人的记忆不可靠，清单可以兜底。", "tags": "检查清单,决策,系统", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 206, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "方法论", "quote": "把每天的时间花在阅读和思考上。芒格说：我认识的聪明人没有不大量阅读的，一个都没有。", "source": "《穷查理宝典》", "interpretation": "芒格被称为长着两条腿的书架。他一生都在通过阅读来扩展自己的认知边界。", "tags": "阅读,学习,习惯", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 207, "figure_id": "munger", "dimension_id": "li-xiang", "category": "经典语录", "quote": "嫉妒是最愚蠢的罪，因为它是唯一一种你永远得不到任何快乐的罪。", "source": "《穷查理宝典》", "interpretation": "芒格说嫉妒驱动世界的程度甚至超过贪婪。但嫉妒带来的只有痛苦，没有快乐。", "tags": "嫉妒,愚蠢,智慧", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 208, "figure_id": "munger", "dimension_id": "ling-dao", "category": "方法论", "quote": "选对人比培养人重要得多。你可以教会一只火鸡爬树，但不如直接雇一只松鼠。", "source": "《穷查理宝典》", "interpretation": "招聘是管理中最关键的决策。选错人，再好的培养体系也补救不了。", "tags": "招聘,用人,管理", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "领导力与管理"}, {"id": 209, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "在能力圈内行动，在能力圈外学习。投资不要超出自己的能力范围。", "source": "《穷查理宝典》第4讲", "interpretation": "这是能力圈原则的行动指南：在懂的领域做决策，在不懂的领域先学习再决策。", "tags": "能力圈,边界,学习", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 210, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "方法论", "quote": "学习和思维是一个持续的过程，不是毕业了就可以停止的事。终身学习是应对世界变化的最佳策略。", "source": "《穷查理宝典》第1讲", "interpretation": "芒格99岁还在每天阅读。对他来说，学习不是任务，而是生活方式。", "tags": "终身学习,成长,习惯", "created_at": "2026-07-06 23:42:33", "updated_at": "2026-07-06 23:42:33", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 211, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "如果你过得比你的邻居好，你会觉得很快乐。如果你过得比你的邻居差，你会觉得很痛苦。所以，降低你的比较标准是最简单获得快乐的方式。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格长寿幸福的秘诀之一：不嫉妒不攀比。幸福不是你拥有多少，而是你对拥有的满意。", "tags": "幸福,比较,满足", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 212, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "分散投资是保护无知的一种方式。如果你知道自己在做什么，你应该集中投资。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格反对过度分散。能力圈内应该集中。", "tags": "集中投资,分散,能力圈", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 213, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "做投资不需要高智商，需要的是能控制自己的情绪。大部分聪明人做投资亏钱，不是因为智商不够，而是因为情绪控制不住。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格反复强调：投资中性格比智商重要得多。能控制情绪的人长期看一定会赢。", "tags": "情绪,理性,性格", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 214, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "我总是试图远离那些明显愚蠢的事情。我一生都在寻找什么是不应该做的，然后避免做它们。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格的逆向思维：先搞清楚什么会让你失败，然后坚决避开。", "tags": "逆向思维,避免,人生", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 215, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "投资银行是危险的。它们的商业模式是在你最需要钱的时候告诉你不能取钱。我从来不信任它们。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格批评投资银行是高杠杆赌博机器。伯克希尔几乎从不投资大型投行。", "tags": "银行,风险,杠杆", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 216, "figure_id": "munger", "dimension_id": "tou-zi", "category": "核心思想", "quote": "比亚迪是我最好的投资之一。我投资比亚迪不是因为我对汽车有什么了解，而是因为我看对了王传福这个人。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格投资比亚迪说明：投资归根结底是投人。他看中王传福的工程师精神和执行力。", "tags": "比亚迪,选人,投资", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 217, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "如果你想变得聪明，你必须不断地问为什么。不是问一次，而是要一直问。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格认为好奇心是智慧的源泉，不断追问根本原因是格栅理论的实践基础。", "tags": "好奇心,学习,思维", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 218, "figure_id": "munger", "dimension_id": "ling-dao", "category": "方法论", "quote": "最好的公司是那些能够自我管理的公司。管理层不需要被监控，他们自己就会做正确的事。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格推崇信任和放权的管理方式。好的管理系统应该让好人能做事、坏人不做坏事。", "tags": "管理,信任,放权", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "领导力与管理"}, {"id": 219, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "最好的婚姻不是找完美的人，而是找一个愿意和你一起面对不完美的人。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格的婚姻观：没有完美的伴侣，但有愿意共同成长的关系。", "tags": "婚姻,关系,成长", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 220, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "芒格30岁时失去了一个眼睛，后来学会了用一只眼睛阅读和生活。他说：生活一定会给你打击，关键是你能不能继续前进。", "source": "《查理·芒格传》", "interpretation": "芒格一生遭遇多次重大打击：离婚、丧子、眼盲。但他始终保持极强的韧性。", "tags": "韧性,打击,生活", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 221, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "经典语录", "quote": "芒格年轻时在巴菲特祖父的杂货店打工，每天12小时。那段艰苦时期教会了他勤奋的价值。", "source": "《查理·芒格传》", "interpretation": "芒格的勤奋和务实源于早年的磨练。他和巴菲特的友谊也从那时开始萌芽。", "tags": "勤奋,早年,经历", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 222, "figure_id": "munger", "dimension_id": "tou-zi", "category": "核心思想", "quote": "芒格说服巴菲特从捡烟蒂策略转向以合理价格买好公司：以合理价格买好公司，好过以便宜价格买烂公司。", "source": "《查理·芒格传》", "interpretation": "这是芒格对伯克希尔最大的贡献——把巴菲特从捡烟蒂转向投优质企业。这一转变直接造就了伯克希尔的辉煌。", "tags": "价值投资,转变,伯克希尔", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 223, "figure_id": "munger", "dimension_id": "gong-zuo", "category": "方法论", "quote": "芒格每天花大量时间阅读和思考。他说：如果我一年不阅读，我就会变成一个傻瓜。", "source": "《查理·芒格传》", "interpretation": "芒格的阅读量惊人，每天4-6小时。他认为阅读不是工作，而是生活方式。", "tags": "阅读,习惯,学习", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "工作方法"}, {"id": 224, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "芒格认为教育孩子最重要的是身教。你对孩子最大的影响不是你说什么，而是你做什么。", "source": "《查理·芒格传》", "interpretation": "芒格自己就是终身阅读者的典范，他的孩子们都养成了阅读习惯。", "tags": "教育,身教,榜样", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 225, "figure_id": "munger", "dimension_id": "ling-dao", "category": "方法论", "quote": "芒格在伯克希尔的角色是二把手但他并不在意头衔。他说：重要的不是你叫什么名字，而是你能贡献什么。", "source": "《查理·芒格传》", "interpretation": "芒格和巴菲特合作了60年从未争夺过权力。这种长期稳定的合作关系本身就是一个奇迹。", "tags": "合作,谦逊,角色", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "领导力与管理"}, {"id": 226, "figure_id": "munger", "dimension_id": "tou-zi", "category": "核心思想", "quote": "我对中国感到非常舒服。我认为中国有巨大的机会，中国的公司比美国的公司更强大、增长更快。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格看好中国市场，通过投资比亚迪获得了巨大回报。他认为中国优秀公司性价比高于美国同类公司。", "tags": "中国,价值投资,全球化", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 227, "figure_id": "munger", "dimension_id": "tou-zi", "category": "核心思想", "quote": "比特币是毒药。它不会成为全球货币。我对比特币的憎恨就像我认为它应该被憎恨一样。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格多年来反复批评加密货币，认为它是赌博工具而不是货币或黄金替代品。", "tags": "比特币,加密货币,风险", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 228, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "我一生都在寻找可以重仓的投资机会。当你找到这样的机会时，你必须下重注。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格强调：罕见的好机会来临时不要小打小闹。大部分人具备识别机会的能力但不具备重仓的勇气。", "tags": "重仓,机会,集中", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 229, "figure_id": "munger", "dimension_id": "xiu-shen", "category": "人生智慧", "quote": "我九十九岁了，我的建议是：不要嫉妒，不要怨恨，不要过度消费，保持乐观。和快乐的人在一起，做自己感兴趣的事。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格晚年反复被问及长寿秘诀，答案始终如一：不嫉妒不怨恨不过度消费。", "tags": "长寿,幸福,人生", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "修身与学习"}, {"id": 230, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "一生只需做少数几个重大的决策，然后持有。剩下的时间你什么都不用做。", "source": "《芒格之道》Daily Journal股东大会", "interpretation": "芒格和巴菲特一生中最重要的10个投资决策占了伯克希尔总收益的90%以上。", "tags": "长期,耐心,集中", "created_at": "2026-07-06 23:45:06", "updated_at": "2026-07-06 23:45:06", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 231, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "生命的本质是什么？芒格的回答很简单：学习、思考、做一个可靠的人，然后帮助别人。", "source": "《芒格之道》", "interpretation": "芒格认为人生的意义不在于获取多少，而在于理解多少、贡献多少。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 232, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "人生的方向应该是：每天起床的时候，争取变得比你从前更聪明一点。长期积累下来，你会得到你应得的东西。", "source": "《穷查理宝典》", "interpretation": "芒格的人生方向不是赚多少钱，而是每天进步一点点。财富是认知的副产品。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 233, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "生命的态度：理性乐观主义——看清世界的真相，但不因此悲观。承认问题的存在，同时相信问题可以被解决。", "source": "《芒格之道》", "interpretation": "芒格是理性乐观主义者：知道事情可能变坏，但相信通过努力可以让它变好。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 234, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "如何知道自己想要什么？你必须去做，去试错，去经历。坐在那里想是想不出来的。实践会告诉你答案。", "source": "《芒格之道》", "interpretation": "芒格认为大多数人不知道自己想要什么，是因为经历太少。多做事多尝试多失败，答案自然出现。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 235, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "如何了解别人？不要听他们说什么，看他们做什么。人的行为比语言诚实得多。", "source": "《芒格之道》", "interpretation": "芒格看人的方法：观察一个人在压力下、在无人监督时、在没有利益驱动时的行为。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 236, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "了解一个人最好的方法不是跟他聊天，是看他的选择。一个人在关键节点上做的选择比聊一百个小时更能说明他是谁。", "source": "《芒格之道》", "interpretation": "芒格认为看一个人在大事上的选择：选什么样的伴侣、选什么职业、怎么面对失败。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 237, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "最终的归宿是什么？芒格说：你的声誉是你最宝贵的资产。它可能需要20年才能建立，但5分钟就能毁掉。", "source": "《穷查理宝典》", "interpretation": "芒格认为人最终的归宿不是金钱地位，而是你留下了什么：声誉、思想、你影响过的人。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 238, "figure_id": "munger", "dimension_id": "li-xiang", "category": "人生智慧", "quote": "我一生中遇到的所有明智的人，没有一个不是大量阅读的。阅读是了解自己和了解世界最好的方式。", "source": "《穷查理宝典》", "interpretation": "芒格认为阅读是解答生命问题的根本方法。想了解自己？读书。想了解别人？读书。", "tags": "munger,li-xiang", "created_at": "2026-07-06 23:57:13", "updated_at": "2026-07-06 23:57:13", "figure_name": "查理·芒格", "dimension_name": "理想与境界"}, {"id": 239, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "如果回到20岁，我会做三件事：选一个我懂的领域深耕、节俭生活积累本金、耐心等待好的投资机会。", "source": "《芒格之道》", "interpretation": "芒格的20岁建议：能力圈+节俭+耐心。不靠暴利，靠复利。", "tags": "芒格,理财,复利", "created_at": "2026-07-07 00:08:26", "updated_at": "2026-07-07 00:08:26", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 240, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "成为百万富翁的方法不是追求高收益，是避免重大损失。长期下来，不亏钱自然就赚钱了。", "source": "《穷查理宝典》", "interpretation": "反过来想：先研究怎么不亏钱，赚钱自然会发生。", "tags": "投资,风险,复利", "created_at": "2026-07-07 00:08:26", "updated_at": "2026-07-07 00:08:26", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 241, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "20多岁最应该投资的是你自己的能力。你把自己的认知提升上去了，赚钱是自然的结果。", "source": "《芒格之道》", "interpretation": "芒格认为年轻时的最佳投资不是股票，是投资自己的大脑。阅读、学习、建立思维模型。", "tags": "自我投资,学习,成长", "created_at": "2026-07-07 00:08:26", "updated_at": "2026-07-07 00:08:26", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}, {"id": 242, "figure_id": "munger", "dimension_id": "tou-zi", "category": "投资哲学", "quote": "巴菲特和我不是靠智商做到的，是靠理性能控制情绪。大部分聪明人赔钱是因为控制不住自己。", "source": "《芒格之道》", "interpretation": "成为百万富翁最关键的因素不是高智商，是情绪控制能力。不追涨、不恐慌、不受外界影响。", "tags": "情绪,理性,投资", "created_at": "2026-07-07 00:08:26", "updated_at": "2026-07-07 00:08:26", "figure_name": "查理·芒格", "dimension_name": "投资与理财"}]};

